     1→/**
     2→ * Viewport State Machine (XState v5)
     3→ *
     4→ * Manages viewport state including zoom, pan, and LOD (Level of Detail).
     5→ * Follows FSM pattern for deterministic, testable state management.
     6→ */
     7→
     8→import { createMachine, assign } from 'xstate';
     9→import type { LODLevel } from '../data/mock-config';
    10→import { LOD_THRESHOLDS, TIME_RANGE, TOTAL_TRAINS, ANIMATION } from '../data/mock-config';
    11→
    12→// =============================================================================
    13→// TYPES
    14→// =============================================================================
    15→
    16→export interface ViewportContext {
    17→  // Camera position
    18→  zoom: number;
    19→  panX: number; // World X (time axis, in days)
    20→  panY: number; // World Y (train axis, in train indices)
    21→
    22→  // LOD state
    23→  lod: LODLevel;
    24→  prevLod: LODLevel | null;
    25→  lodTransitionProgress: number; // 0-1 for crossfade
    26→
    27→  // Viewport dimensions
    28→  viewportWidth: number;
    29→  viewportHeight: number;
    30→
    31→  // Animation state
    32→  targetZoom: number | null;
    33→  targetPanX: number | null;
    34→  targetPanY: number | null;
    35→  animationStartTime: number | null;
    36→  animationDuration: number;
    37→  animationStartZoom: number;
    38→  animationStartPanX: number;
    39→  animationStartPanY: number;
    40→
    41→  // Momentum state (for inertial panning)
    42→  velocityX: number;
    43→  velocityY: number;
    44→
    45→  // Interaction state
    46→  isPinching: boolean;
    47→  pinchStartZoom: number;
    48→  pointerStartX: number;
    49→  pointerStartY: number;
    50→  panStartX: number;
    51→  panStartY: number;
    52→}
    53→
    54→export type ViewportEvent =
    55→  | { type: 'ZOOM'; delta: number; centerX: number; centerY: number }
    56→  | { type: 'ZOOM_TO'; zoom: number; centerX?: number; centerY?: number; animate?: boolean }
    57→  | { type: 'PAN'; deltaX: number; deltaY: number }
    58→  | { type: 'PAN_TO'; x: number; y: number; animate?: boolean }
    59→  | { type: 'PAN_START'; pointerX: number; pointerY: number }
    60→  | { type: 'PAN_MOVE'; pointerX: number; pointerY: number }
    61→  | { type: 'PAN_END'; velocityX?: number; velocityY?: number }
    62→  | { type: 'PINCH_START'; zoom: number }
    63→  | { type: 'PINCH_MOVE'; scale: number; centerX: number; centerY: number }
    64→  | { type: 'PINCH_END' }
    65→  | { type: 'DOUBLE_TAP'; x: number; y: number }
    66→  | { type: 'RESET' }
    67→  | { type: 'JUMP_TO_TODAY' }
    68→  | { type: 'JUMP_TO_TRAIN'; trainIndex: number }
    69→  | { type: 'ANIMATION_TICK'; timestamp: number }
    70→  | { type: 'MOMENTUM_TICK'; timestamp: number }
    71→  | { type: 'LOD_TRANSITION_COMPLETE' }
    72→  | { type: 'RESIZE'; width: number; height: number };
    73→
    74→// =============================================================================
    75→// CONSTANTS
    76→// =============================================================================
    77→
    78→const MIN_ZOOM = 0.1;
    79→const MAX_ZOOM = 10;
    80→const ZOOM_SENSITIVITY = 0.002;
    81→const DOUBLE_TAP_ZOOM_FACTOR = 2;
    82→const MOMENTUM_FRICTION = 0.92;
    83→const MOMENTUM_MIN_VELOCITY = 0.5;
    84→
    85→// World bounds
    86→const WORLD_MIN_X = 0;
    87→const WORLD_MAX_X = TIME_RANGE.days; // 4383 days
    88→const WORLD_MIN_Y = 0;
    89→const WORLD_MAX_Y = TOTAL_TRAINS; // 128 trains
    90→
    91→// =============================================================================
    92→// HELPER FUNCTIONS
    93→// =============================================================================
    94→
    95→function getLODLevel(zoom: number): LODLevel {
    96→  if (zoom < LOD_THRESHOLDS.strategic) return 'strategic';
    97→  if (zoom < LOD_THRESHOLDS.tactical) return 'tactical';
    98→  if (zoom < LOD_THRESHOLDS.operational) return 'operational';
    99→  return 'execution';
   100→}
   101→
   102→function clamp(value: number, min: number, max: number): number {
   103→  return Math.max(min, Math.min(max, value));
   104→}
   105→
   106→function clampZoom(zoom: number): number {
   107→  return clamp(zoom, MIN_ZOOM, MAX_ZOOM);
   108→}
   109→
   110→function clampPan(x: number, y: number): { x: number; y: number } {
   111→  return {
   112→    x: clamp(x, WORLD_MIN_X, WORLD_MAX_X),
   113→    y: clamp(y, WORLD_MIN_Y, WORLD_MAX_Y),
   114→  };
   115→}
   116→
   117→// Ease out expo for smooth animations
   118→function easeOutExpo(t: number): number {
   119→  return t === 1 ? 1 : 1 - Math.pow(2, -10 * t);
   120→}
   121→
   122→// Get "today" position in days from start
   123→function getTodayDayIndex(): number {
   124→  const today = new Date();
   125→  const start = TIME_RANGE.start;
   126→  const diffMs = today.getTime() - start.getTime();
   127→  const diffDays = Math.floor(diffMs / (1000 * 60 * 60 * 24));
   128→  return clamp(diffDays, 0, TIME_RANGE.days);
   129→}
   130→
   131→// =============================================================================
   132→// INITIAL CONTEXT
   133→// =============================================================================
   134→
   135→const initialContext: ViewportContext = {
   136→  zoom: 0.2, // Start at strategic level
   137→  panX: 0,
   138→  panY: TOTAL_TRAINS / 2, // Center on trains
   139→
   140→  lod: 'strategic',
   141→  prevLod: null,
   142→  lodTransitionProgress: 1,
   143→
   144→  viewportWidth: 1200,
   145→  viewportHeight: 800,
   146→
   147→  targetZoom: null,
   148→  targetPanX: null,
   149→  targetPanY: null,
   150→  animationStartTime: null,
   151→  animationDuration: ANIMATION.duration.zoom,
   152→  animationStartZoom: 0.2,
   153→  animationStartPanX: 0,
   154→  animationStartPanY: TOTAL_TRAINS / 2,
   155→
   156→  velocityX: 0,
   157→  velocityY: 0,
   158→
   159→  isPinching: false,
   160→  pinchStartZoom: 1,
   161→  pointerStartX: 0,
   162→  pointerStartY: 0,
   163→  panStartX: 0,
   164→  panStartY: 0,
   165→};
   166→
   167→// =============================================================================
   168→// STATE MACHINE
   169→// =============================================================================
   170→
   171→export const viewportMachine = createMachine({
   172→  id: 'viewport',
   173→  initial: 'idle',
   174→  context: initialContext,
   175→  states: {
   176→    idle: {
   177→      on: {
   178→        ZOOM: {
   179→          actions: assign(({ context, event }) => {
   180→            const zoomFactor = 1 - event.delta * ZOOM_SENSITIVITY;
   181→            const newZoom = clampZoom(context.zoom * zoomFactor);
   182→
   183→            // Zoom toward cursor position
   184→            const zoomRatio = newZoom / context.zoom;
   185→            const newPanX = event.centerX - (event.centerX - context.panX) * zoomRatio;
   186→            const newPanY = event.centerY - (event.centerY - context.panY) * zoomRatio;
   187→            const clamped = clampPan(newPanX, newPanY);
   188→
   189→            const newLod = getLODLevel(newZoom);
   190→            const lodChanged = newLod !== context.lod;
   191→
   192→            return {
   193→              zoom: newZoom,
   194→              panX: clamped.x,
   195→              panY: clamped.y,
   196→              lod: newLod,
   197→              prevLod: lodChanged ? context.lod : context.prevLod,
   198→              lodTransitionProgress: lodChanged ? 0 : context.lodTransitionProgress,
   199→            };
   200→          }),
   201→        },
   202→        ZOOM_TO: {
   203→          target: 'animating',
   204→          actions: assign(({ context, event }) => ({
   205→            targetZoom: clampZoom(event.zoom),
   206→            targetPanX: event.centerX ?? context.panX,
   207→            targetPanY: event.centerY ?? context.panY,
   208→            animationStartTime: performance.now(),
   209→            animationDuration: event.animate === false ? 0 : ANIMATION.duration.zoom,
   210→            animationStartZoom: context.zoom,
   211→            animationStartPanX: context.panX,
   212→            animationStartPanY: context.panY,
   213→          })),
   214→        },
   215→        PAN: {
   216→          actions: assign(({ context, event }) => {
   217→            const clamped = clampPan(
   218→              context.panX - event.deltaX / context.zoom,
   219→              context.panY - event.deltaY / context.zoom
   220→            );
   221→            return {
   222→              panX: clamped.x,
   223→              panY: clamped.y,
   224→            };
   225→          }),
   226→        },
   227→        PAN_START: {
   228→          target: 'panning',
   229→          actions: assign(({ context, event }) => ({
   230→            pointerStartX: event.pointerX,
   231→            pointerStartY: event.pointerY,
   232→            panStartX: context.panX,
   233→            panStartY: context.panY,
   234→            velocityX: 0,
   235→            velocityY: 0,
   236→          })),
   237→        },
   238→        PAN_TO: {
   239→          target: 'animating',
   240→          actions: assign(({ context, event }) => ({
   241→            targetZoom: context.zoom,
   242→            targetPanX: event.x,
   243→            targetPanY: event.y,
   244→            animationStartTime: performance.now(),
   245→            animationDuration: event.animate === false ? 0 : ANIMATION.duration.zoom,
   246→            animationStartZoom: context.zoom,
   247→            animationStartPanX: context.panX,
   248→            animationStartPanY: context.panY,
   249→          })),
   250→        },
   251→        PINCH_START: {
   252→          target: 'pinching',
   253→          actions: assign(({ context, event }) => ({
   254→            isPinching: true,
   255→            pinchStartZoom: context.zoom,
   256→          })),
   257→        },
   258→        DOUBLE_TAP: {
   259→          target: 'animating',
   260→          actions: assign(({ context, event }) => {
   261→            const newZoom = clampZoom(context.zoom * DOUBLE_TAP_ZOOM_FACTOR);
   262→            return {
   263→              targetZoom: newZoom,
   264→              targetPanX: event.x,
   265→              targetPanY: event.y,
   266→              animationStartTime: performance.now(),
   267→              animationDuration: ANIMATION.duration.zoom,
   268→              animationStartZoom: context.zoom,
   269→              animationStartPanX: context.panX,
   270→              animationStartPanY: context.panY,
   271→            };
   272→          }),
   273→        },
   274→        RESET: {
   275→          target: 'animating',
   276→          actions: assign(({ context }) => ({
   277→            targetZoom: initialContext.zoom,
   278→            targetPanX: initialContext.panX,
   279→            targetPanY: initialContext.panY,
   280→            animationStartTime: performance.now(),
   281→            animationDuration: ANIMATION.duration.zoom,
   282→            animationStartZoom: context.zoom,
   283→            animationStartPanX: context.panX,
   284→            animationStartPanY: context.panY,
   285→          })),
   286→        },
   287→        JUMP_TO_TODAY: {
   288→          target: 'animating',
   289→          actions: assign(({ context }) => ({
   290→            targetZoom: 1.0, // Tactical level
   291→            targetPanX: getTodayDayIndex(),
   292→            targetPanY: context.panY,
   293→            animationStartTime: performance.now(),
   294→            animationDuration: ANIMATION.duration.zoom,
   295→            animationStartZoom: context.zoom,
   296→            animationStartPanX: context.panX,
   297→            animationStartPanY: context.panY,
   298→          })),
   299→        },
   300→        JUMP_TO_TRAIN: {
   301→          target: 'animating',
   302→          actions: assign(({ context, event }) => ({
   303→            targetZoom: context.zoom,
   304→            targetPanX: context.panX,
   305→            targetPanY: event.trainIndex,
   306→            animationStartTime: performance.now(),
   307→            animationDuration: ANIMATION.duration.zoom,
   308→            animationStartZoom: context.zoom,
   309→            animationStartPanX: context.panX,
   310→            animationStartPanY: context.panY,
   311→          })),
   312→        },
   313→        RESIZE: {
   314→          actions: assign(({ event }) => ({
   315→            viewportWidth: event.width,
   316→            viewportHeight: event.height,
   317→          })),
   318→        },
   319→        LOD_TRANSITION_COMPLETE: {
   320→          actions: assign(() => ({
   321→            lodTransitionProgress: 1,
   322→            prevLod: null,
   323→          })),
   324→        },
   325→      },
   326→    },
   327→    panning: {
   328→      on: {
   329→        PAN_MOVE: {
   330→          actions: assign(({ context, event }) => {
   331→            const deltaX = (event.pointerX - context.pointerStartX) / context.zoom;
   332→            const deltaY = (event.pointerY - context.pointerStartY) / context.zoom;
   333→            const clamped = clampPan(
   334→              context.panStartX - deltaX,
   335→              context.panStartY - deltaY
   336→            );
   337→
   338→            // Calculate velocity for momentum
   339→            const velocityX = (context.panX - clamped.x) * 0.5;
   340→            const velocityY = (context.panY - clamped.y) * 0.5;
   341→
   342→            return {
   343→              panX: clamped.x,
   344→              panY: clamped.y,
   345→              velocityX,
   346→              velocityY,
   347→            };
   348→          }),
   349→        },
   350→        PAN_END: [
   351→          {
   352→            target: 'momentum',
   353→            guard: ({ context }) =>
   354→              Math.abs(context.velocityX) > MOMENTUM_MIN_VELOCITY ||
   355→              Math.abs(context.velocityY) > MOMENTUM_MIN_VELOCITY,
   356→          },
   357→          {
   358→            target: 'idle',
   359→          },
   360→        ],
   361→        ZOOM: {
   362→          actions: assign(({ context, event }) => {
   363→            const zoomFactor = 1 - event.delta * ZOOM_SENSITIVITY;
   364→            const newZoom = clampZoom(context.zoom * zoomFactor);
   365→            const newLod = getLODLevel(newZoom);
   366→            const lodChanged = newLod !== context.lod;
   367→
   368→            return {
   369→              zoom: newZoom,
   370→              lod: newLod,
   371→              prevLod: lodChanged ? context.lod : context.prevLod,
   372→              lodTransitionProgress: lodChanged ? 0 : context.lodTransitionProgress,
   373→            };
   374→          }),
   375→        },
   376→      },
   377→    },
   378→    pinching: {
   379→      on: {
   380→        PINCH_MOVE: {
   381→          actions: assign(({ context, event }) => {
   382→            const newZoom = clampZoom(context.pinchStartZoom * event.scale);
   383→
   384→            // Zoom toward pinch center
   385→            const zoomRatio = newZoom / context.zoom;
   386→            const newPanX = event.centerX - (event.centerX - context.panX) * zoomRatio;
   387→            const newPanY = event.centerY - (event.centerY - context.panY) * zoomRatio;
   388→            const clamped = clampPan(newPanX, newPanY);
   389→
   390→            const newLod = getLODLevel(newZoom);
   391→            const lodChanged = newLod !== context.lod;
   392→
   393→            return {
   394→              zoom: newZoom,
   395→              panX: clamped.x,
   396→              panY: clamped.y,
   397→              lod: newLod,
   398→              prevLod: lodChanged ? context.lod : context.prevLod,
   399→              lodTransitionProgress: lodChanged ? 0 : context.lodTransitionProgress,
   400→            };
   401→          }),
   402→        },
   403→        PINCH_END: {
   404→          target: 'idle',
   405→          actions: assign(() => ({
   406→            isPinching: false,
   407→          })),
   408→        },
   409→      },
   410→    },
   411→    momentum: {
   412→      on: {
   413→        MOMENTUM_TICK: [
   414→          {
   415→            target: 'idle',
   416→            guard: ({ context }) =>
   417→              Math.abs(context.velocityX) < MOMENTUM_MIN_VELOCITY &&
   418→              Math.abs(context.velocityY) < MOMENTUM_MIN_VELOCITY,
   419→          },
   420→          {
   421→            actions: assign(({ context }) => {
   422→              const clamped = clampPan(
   423→                context.panX + context.velocityX,
   424→                context.panY + context.velocityY
   425→              );
   426→              return {
   427→                panX: clamped.x,
   428→                panY: clamped.y,
   429→                velocityX: context.velocityX * MOMENTUM_FRICTION,
   430→                velocityY: context.velocityY * MOMENTUM_FRICTION,
   431→              };
   432→            }),
   433→          },
   434→        ],
   435→        PAN_START: {
   436→          target: 'panning',
   437→          actions: assign(({ context, event }) => ({
   438→            pointerStartX: event.pointerX,
   439→            pointerStartY: event.pointerY,
   440→            panStartX: context.panX,
   441→            panStartY: context.panY,
   442→            velocityX: 0,
   443→            velocityY: 0,
   444→          })),
   445→        },
   446→        ZOOM: {
   447→          target: 'idle',
   448→          actions: assign(({ context, event }) => {
   449→            const zoomFactor = 1 - event.delta * ZOOM_SENSITIVITY;
   450→            const newZoom = clampZoom(context.zoom * zoomFactor);
   451→            const newLod = getLODLevel(newZoom);
   452→
   453→            return {
   454→              zoom: newZoom,
   455→              lod: newLod,
   456→              velocityX: 0,
   457→              velocityY: 0,
   458→            };
   459→          }),
   460→        },
   461→      },
   462→    },
   463→    animating: {
   464→      on: {
   465→        ANIMATION_TICK: [
   466→          {
   467→            target: 'idle',
   468→            guard: ({ context, event }) => {
   469→              if (!context.animationStartTime) return true;
   470→              const elapsed = event.timestamp - context.animationStartTime;
   471→              return elapsed >= context.animationDuration;
   472→            },
   473→            actions: assign(({ context }) => {
   474→              const finalZoom = context.targetZoom ?? context.animationStartZoom;
   475→              const finalPanX = context.targetPanX ?? context.animationStartPanX;
   476→              const finalPanY = context.targetPanY ?? context.animationStartPanY;
   477→              const newLod = getLODLevel(finalZoom);
   478→              const lodChanged = newLod !== context.lod;
   479→
   480→              return {
   481→                zoom: finalZoom,
   482→                panX: finalPanX,
   483→                panY: finalPanY,
   484→                lod: newLod,
   485→                prevLod: lodChanged ? context.lod : null,
   486→                lodTransitionProgress: lodChanged ? 0 : 1,
   487→                targetZoom: null,
   488→                targetPanX: null,
   489→                targetPanY: null,
   490→                animationStartTime: null,
   491→              };
   492→            }),
   493→          },
   494→          {
   495→            actions: assign(({ context, event }) => {
   496→              if (!context.animationStartTime) return {};
   497→
   498→              const elapsed = event.timestamp - context.animationStartTime;
   499→              const progress = Math.min(1, elapsed / context.animationDuration);
   500→              const eased = easeOutExpo(progress);
   501→
   502→              const startZoom = context.animationStartZoom;
   503→              const startPanX = context.animationStartPanX;
   504→              const startPanY = context.animationStartPanY;
   505→              const targetZoom = context.targetZoom ?? startZoom;
   506→              const targetPanX = context.targetPanX ?? startPanX;
   507→              const targetPanY = context.targetPanY ?? startPanY;
   508→
   509→              const newZoom = startZoom + (targetZoom - startZoom) * eased;
   510→              const newPanX = startPanX + (targetPanX - startPanX) * eased;
   511→              const newPanY = startPanY + (targetPanY - startPanY) * eased;
   512→
   513→              const newLod = getLODLevel(newZoom);
   514→
   515→              return {
   516→                zoom: newZoom,
   517→                panX: newPanX,
   518→                panY: newPanY,
   519→                lod: newLod,
   520→              };
   521→            }),
   522→          },
   523→        ],
   524→        PAN_START: {
   525→          target: 'panning',
   526→          actions: assign(({ context, event }) => ({
   527→            // Cancel animation
   528→            targetZoom: null,
   529→            targetPanX: null,
   530→            targetPanY: null,
   531→            animationStartTime: null,
   532→            // Start panning
   533→            pointerStartX: event.pointerX,
   534→            pointerStartY: event.pointerY,
   535→            panStartX: context.panX,
   536→            panStartY: context.panY,
   537→            velocityX: 0,
   538→            velocityY: 0,
   539→          })),
   540→        },
   541→      },
   542→    },
   543→  },
   544→});
   545→
   546→// =============================================================================
   547→// EXPORTS
   548→// =============================================================================
   549→
   550→export type ViewportMachine = typeof viewportMachine;
   551→export type ViewportState = ReturnType<typeof viewportMachine.getInitialSnapshot>;
   552→

