     1→/**
     2→ * MMS Mock Data Generator
     3→ *
     4→ * Generates realistic maintenance data for 128 trains over 12 years.
     5→ * Produces ~60,000 tasks with proper mileage-based intervals.
     6→ */
     7→
     8→import type { FleetConfig, MaintenanceType, MaintenanceTypeId, TaskStatus } from './mock-config';
     9→import {
    10→  FLEETS,
    11→  TIME_RANGE,
    12→  MAINTENANCE_TYPES,
    13→  MAINTENANCE_TYPE_MAP,
    14→  MILEAGE,
    15→  RESOURCES,
    16→} from './mock-config';
    17→
    18→// =============================================================================
    19→// TYPES
    20→// =============================================================================
    21→
    22→export interface Train {
    23→  id: string;
    24→  name: string;
    25→  fleetId: string;
    26→  fleetName: string;
    27→  index: number; // 0-127
    28→  currentMileageKm: number;
    29→  avgDailyMileageKm: number;
    30→}
    31→
    32→export interface Task {
    33→  id: string;
    34→  trainId: string;
    35→  trainIndex: number;
    36→  type: MaintenanceTypeId;
    37→  name: string;
    38→  startDate: Date;
    39→  endDate: Date;
    40→  durationHours: number;
    41→  manHours: number;
    42→  costAed: number;
    43→  status: TaskStatus;
    44→  pitId?: number;
    45→  technicians?: number;
    46→  partsReady?: boolean;
    47→  hasConflict: boolean;
    48→  color: string;
    49→}
    50→
    51→export interface AggregatedCell {
    52→  trainIndex: number;
    53→  periodIndex: number; // quarter index for strategic, month for tactical
    54→  totalTasks: number;
    55→  totalManHours: number;
    56→  totalCostAed: number;
    57→  tasksByType: Record<MaintenanceTypeId, number>;
    58→  hasOverhaul: boolean;
    59→  utilizationPercent: number;
    60→}
    61→
    62→export interface MockData {
    63→  trains: Train[];
    64→  tasks: Task[];
    65→  aggregatedByQuarter: AggregatedCell[];
    66→  aggregatedByMonth: AggregatedCell[];
    67→  stats: {
    68→    totalTrains: number;
    69→    totalTasks: number;
    70→    totalManHours: number;
    71→    totalCostAed: number;
    72→    avgTasksPerTrain: number;
    73→    conflictCount: number;
    74→  };
    75→}
    76→
    77→// =============================================================================
    78→// RANDOM UTILITIES
    79→// =============================================================================
    80→
    81→// Seeded random for reproducibility
    82→let seed = 12345;
    83→
    84→function seededRandom(): number {
    85→  seed = (seed * 1103515245 + 12345) & 0x7fffffff;
    86→  return seed / 0x7fffffff;
    87→}
    88→
    89→function resetSeed(newSeed: number = 12345): void {
    90→  seed = newSeed;
    91→}
    92→
    93→function randomInRange(min: number, max: number): number {
    94→  return min + seededRandom() * (max - min);
    95→}
    96→
    97→function randomInt(min: number, max: number): number {
    98→  return Math.floor(randomInRange(min, max + 1));
    99→}
   100→
   101→function randomChoice<T>(arr: T[]): T {
   102→  return arr[Math.floor(seededRandom() * arr.length)];
   103→}
   104→
   105→// =============================================================================
   106→// DATE UTILITIES
   107→// =============================================================================
   108→
   109→function addDays(date: Date, days: number): Date {
   110→  const result = new Date(date);
   111→  result.setDate(result.getDate() + days);
   112→  return result;
   113→}
   114→
   115→function addHours(date: Date, hours: number): Date {
   116→  const result = new Date(date);
   117→  result.setTime(result.getTime() + hours * 60 * 60 * 1000);
   118→  return result;
   119→}
   120→
   121→function daysBetween(start: Date, end: Date): number {
   122→  return Math.floor((end.getTime() - start.getTime()) / (1000 * 60 * 60 * 24));
   123→}
   124→
   125→function getQuarterIndex(date: Date): number {
   126→  const year = date.getFullYear() - 2024;
   127→  const quarter = Math.floor(date.getMonth() / 3);
   128→  return year * 4 + quarter;
   129→}
   130→
   131→function getMonthIndex(date: Date): number {
   132→  const year = date.getFullYear() - 2024;
   133→  const month = date.getMonth();
   134→  return year * 12 + month;
   135→}
   136→
   137→// =============================================================================
   138→// TRAIN GENERATION
   139→// =============================================================================
   140→
   141→function generateTrains(): Train[] {
   142→  const trains: Train[] = [];
   143→  let globalIndex = 0;
   144→
   145→  for (const fleet of FLEETS) {
   146→    for (let i = 0; i < fleet.count; i++) {
   147→      const trainNumber = String(i + 1).padStart(3, '0');
   148→      const avgDailyMileage = MILEAGE.average_daily_km * (1 + randomInRange(-MILEAGE.variance, MILEAGE.variance));
   149→
   150→      // Initial mileage: trains have been running since before 2024
   151→      // Assume 1-5 years of prior operation
   152→      const priorYears = randomInRange(1, 5);
   153→      const initialMileage = avgDailyMileage * 365 * priorYears;
   154→
   155→      trains.push({
   156→        id: `${fleet.prefix}-${trainNumber}`,
   157→        name: `${fleet.name} ${trainNumber}`,
   158→        fleetId: fleet.id,
   159→        fleetName: fleet.name,
   160→        index: globalIndex,
   161→        currentMileageKm: Math.round(initialMileage),
   162→        avgDailyMileageKm: Math.round(avgDailyMileage),
   163→      });
   164→      globalIndex++;
   165→    }
   166→  }
   167→
   168→  return trains;
   169→}
   170→
   171→// =============================================================================
   172→// TASK GENERATION
   173→// =============================================================================
   174→
   175→function generateTasksForTrain(train: Train, taskIdCounter: { value: number }): Task[] {
   176→  const tasks: Task[] = [];
   177→  let currentMileage = train.currentMileageKm;
   178→  let currentDate = new Date(TIME_RANGE.start);
   179→
   180→  // Track next maintenance due for each type
   181→  const nextDue: Record<MaintenanceTypeId, number> = {
   182→    pm1: currentMileage + MAINTENANCE_TYPES[0].interval_km,
   183→    pm2: currentMileage + MAINTENANCE_TYPES[1].interval_km,
   184→    pm3: currentMileage + MAINTENANCE_TYPES[2].interval_km,
   185→    overhaul: currentMileage + MAINTENANCE_TYPES[3].interval_km,
   186→    corrective: 0, // Random
   187→  };
   188→
   189→  // Simulate day by day through 12 years
   190→  while (currentDate < TIME_RANGE.end) {
   191→    // Accumulate daily mileage with variance
   192→    const dailyVariance = 1 + randomInRange(-0.1, 0.1);
   193→    const todayMileage = train.avgDailyMileageKm * dailyVariance;
   194→    currentMileage += todayMileage;
   195→
   196→    // Check for scheduled maintenance triggers
   197→    const typesToSchedule: MaintenanceTypeId[] = [];
   198→
   199→    // Check each maintenance type (except corrective)
   200→    for (const mt of MAINTENANCE_TYPES.slice(0, 4)) {
   201→      if (currentMileage >= nextDue[mt.id]) {
   202→        typesToSchedule.push(mt.id);
   203→        // Reset next due
   204→        nextDue[mt.id] = currentMileage + mt.interval_km;
   205→      }
   206→    }
   207→
   208→    // Random corrective maintenance (~2% daily chance when not in other maintenance)
   209→    if (typesToSchedule.length === 0 && seededRandom() < 0.02) {
   210→      typesToSchedule.push('corrective');
   211→    }
   212→
   213→    // Schedule tasks
   214→    for (const typeId of typesToSchedule) {
   215→      const mt = MAINTENANCE_TYPE_MAP.get(typeId)!;
   216→
   217→      // Add some scheduling variance (±3 days)
   218→      const scheduledDate = addDays(currentDate, randomInt(-3, 7));
   219→
   220→      // Don't schedule in the past
   221→      if (scheduledDate < TIME_RANGE.start) continue;
   222→
   223→      // Don't schedule after end date
   224→      if (scheduledDate >= TIME_RANGE.end) continue;
   225→
   226→      const endDate = addHours(scheduledDate, mt.duration_hours);
   227→
   228→      // Determine status based on date relative to "today" (mid-2030 for demo)
   229→      const today = new Date('2030-06-15');
   230→      let status: TaskStatus = 'scheduled';
   231→
   232→      if (scheduledDate < today) {
   233→        if (endDate < today) {
   234→          status = seededRandom() < 0.95 ? 'completed' : 'overdue';
   235→        } else {
   236→          status = 'in-progress';
   237→        }
   238→      }
   239→
   240→      // Some tasks have conflicts (~8%)
   241→      const hasConflict = seededRandom() < 0.08;
   242→      if (hasConflict) {
   243→        status = 'conflict';
   244→      }
   245→
   246→      const task: Task = {
   247→        id: `TASK-${String(taskIdCounter.value++).padStart(6, '0')}`,
   248→        trainId: train.id,
   249→        trainIndex: train.index,
   250→        type: typeId,
   251→        name: mt.name,
   252→        startDate: scheduledDate,
   253→        endDate: endDate,
   254→        durationHours: mt.duration_hours,
   255→        manHours: mt.man_hours,
   256→        costAed: mt.cost_aed,
   257→        status,
   258→        pitId: randomInt(1, RESOURCES.pits),
   259→        technicians: Math.ceil(mt.man_hours / 8),
   260→        partsReady: seededRandom() < 0.85,
   261→        hasConflict,
   262→        color: mt.color,
   263→      };
   264→
   265→      tasks.push(task);
   266→    }
   267→
   268→    // Advance one day
