/**
 * MMS Mock Data Generator
 *
 * Generates realistic maintenance data for 128 trains over 12 years.
 * Produces ~60,000 tasks with proper mileage-based intervals.
 */

import type { FleetConfig, MaintenanceType, MaintenanceTypeId, TaskStatus } from './mock-config';
import {
  FLEETS,
  TIME_RANGE,
  MAINTENANCE_TYPES,
  MAINTENANCE_TYPE_MAP,
  MILEAGE,
  RESOURCES,
} from './mock-config';

// =============================================================================
// TYPES
// =============================================================================

export interface Train {
  id: string;
  name: string;
  fleetId: string;
  fleetName: string;
  index: number; // 0-127
  currentMileageKm: number;
  avgDailyMileageKm: number;
}

export interface Task {
  id: string;
  trainId: string;
  trainIndex: number;
  type: MaintenanceTypeId;
  name: string;
  startDate: Date;
  endDate: Date;
  durationHours: number;
  manHours: number;
  costAed: number;
  status: TaskStatus;
  pitId?: number;
  technicians?: number;
  partsReady?: boolean;
  hasConflict: boolean;
  color: string;
}

export interface AggregatedCell {
  trainIndex: number;
  periodIndex: number; // quarter index for strategic, month for tactical
  totalTasks: number;
  totalManHours: number;
  totalCostAed: number;
  tasksByType: Record<MaintenanceTypeId, number>;
  hasOverhaul: boolean;
  utilizationPercent: number;
}

export interface MockData {
  trains: Train[];
  tasks: Task[];
  aggregatedByQuarter: AggregatedCell[];
  aggregatedByMonth: AggregatedCell[];
  stats: {
    totalTrains: number;
    totalTasks: number;
    totalManHours: number;
    totalCostAed: number;
    avgTasksPerTrain: number;
    conflictCount: number;
  };
}

// =============================================================================
// RANDOM UTILITIES
// =============================================================================

// Seeded random for reproducibility
let seed = 12345;

function seededRandom(): number {
  seed = (seed * 1103515245 + 12345) & 0x7fffffff;
  return seed / 0x7fffffff;
}

function resetSeed(newSeed: number = 12345): void {
  seed = newSeed;
}

function randomInRange(min: number, max: number): number {
  return min + seededRandom() * (max - min);
}

function randomInt(min: number, max: number): number {
  return Math.floor(randomInRange(min, max + 1));
}

function randomChoice<T>(arr: T[]): T {
  return arr[Math.floor(seededRandom() * arr.length)];
}

// =============================================================================
// DATE UTILITIES
// =============================================================================

function addDays(date: Date, days: number): Date {
  const result = new Date(date);
  result.setDate(result.getDate() + days);
  return result;
}

function addHours(date: Date, hours: number): Date {
  const result = new Date(date);
  result.setTime(result.getTime() + hours * 60 * 60 * 1000);
  return result;
}

function daysBetween(start: Date, end: Date): number {
  return Math.floor((end.getTime() - start.getTime()) / (1000 * 60 * 60 * 24));
}

function getQuarterIndex(date: Date): number {
  const year = date.getFullYear() - 2024;
  const quarter = Math.floor(date.getMonth() / 3);
  return year * 4 + quarter;
}

function getMonthIndex(date: Date): number {
  const year = date.getFullYear() - 2024;
  const month = date.getMonth();
  return year * 12 + month;
}

// =============================================================================
// TRAIN GENERATION
// =============================================================================

function generateTrains(): Train[] {
  const trains: Train[] = [];
  let globalIndex = 0;

  for (const fleet of FLEETS) {
    for (let i = 0; i < fleet.count; i++) {
      const trainNumber = String(i + 1).padStart(3, '0');
      const avgDailyMileage = MILEAGE.average_daily_km * (1 + randomInRange(-MILEAGE.variance, MILEAGE.variance));

      // Initial mileage: trains have been running since before 2024
      // Assume 1-5 years of prior operation
      const priorYears = randomInRange(1, 5);
      const initialMileage = avgDailyMileage * 365 * priorYears;

      trains.push({
        id: `${fleet.prefix}-${trainNumber}`,
        name: `${fleet.name} ${trainNumber}`,
        fleetId: fleet.id,
        fleetName: fleet.name,
        index: globalIndex,
        currentMileageKm: Math.round(initialMileage),
        avgDailyMileageKm: Math.round(avgDailyMileage),
      });
      globalIndex++;
    }
  }

  return trains;
}

// =============================================================================
// TASK GENERATION
// =============================================================================

function generateTasksForTrain(train: Train, taskIdCounter: { value: number }): Task[] {
  const tasks: Task[] = [];
  let currentMileage = train.currentMileageKm;
  let currentDate = new Date(TIME_RANGE.start);

  // Track next maintenance due for each type
  const nextDue: Record<MaintenanceTypeId, number> = {
    pm1: currentMileage + MAINTENANCE_TYPES[0].interval_km,
    pm2: currentMileage + MAINTENANCE_TYPES[1].interval_km,
    pm3: currentMileage + MAINTENANCE_TYPES[2].interval_km,
    overhaul: currentMileage + MAINTENANCE_TYPES[3].interval_km,
    corrective: 0, // Random
  };

  // Simulate day by day through 12 years
  while (currentDate < TIME_RANGE.end) {
    // Accumulate daily mileage with variance
    const dailyVariance = 1 + randomInRange(-0.1, 0.1);
    const todayMileage = train.avgDailyMileageKm * dailyVariance;
    currentMileage += todayMileage;

    // Check for scheduled maintenance triggers
    const typesToSchedule: MaintenanceTypeId[] = [];

    // Check each maintenance type (except corrective)
    for (const mt of MAINTENANCE_TYPES.slice(0, 4)) {
      if (currentMileage >= nextDue[mt.id]) {
        typesToSchedule.push(mt.id);
        // Reset next due
        nextDue[mt.id] = currentMileage + mt.interval_km;
      }
    }

    // Random corrective maintenance (~2% daily chance when not in other maintenance)
    if (typesToSchedule.length === 0 && seededRandom() < 0.02) {
      typesToSchedule.push('corrective');
    }

    // Schedule tasks
    for (const typeId of typesToSchedule) {
      const mt = MAINTENANCE_TYPE_MAP.get(typeId)!;

      // Add some scheduling variance (±3 days)
      const scheduledDate = addDays(currentDate, randomInt(-3, 7));

      // Don't schedule in the past
      if (scheduledDate < TIME_RANGE.start) continue;

      // Don't schedule after end date
      if (scheduledDate >= TIME_RANGE.end) continue;

      const endDate = addHours(scheduledDate, mt.duration_hours);

      // Determine status based on date relative to "today" (mid-2030 for demo)
      const today = new Date('2030-06-15');
      let status: TaskStatus = 'scheduled';

      if (scheduledDate < today) {
        if (endDate < today) {
          status = seededRandom() < 0.95 ? 'completed' : 'overdue';
        } else {
          status = 'in-progress';
        }
      }

      // Some tasks have conflicts (~8%)
      const hasConflict = seededRandom() < 0.08;
      if (hasConflict) {
        status = 'conflict';
      }

      const task: Task = {
        id: `TASK-${String(taskIdCounter.value++).padStart(6, '0')}`,
        trainId: train.id,
        trainIndex: train.index,
        type: typeId,
        name: mt.name,
        startDate: scheduledDate,
        endDate: endDate,
        durationHours: mt.duration_hours,
        manHours: mt.man_hours,
        costAed: mt.cost_aed,
        status,
        pitId: randomInt(1, RESOURCES.pits),
        technicians: Math.ceil(mt.man_hours / 8),
        partsReady: seededRandom() < 0.85,
        hasConflict,
        color: mt.color,
      };

      tasks.push(task);
    }

    // Advance one day
    currentDate = addDays(currentDate, 1);
  }

  return tasks;
}

// =============================================================================
// AGGREGATION
// =============================================================================

function aggregateByQuarter(trains: Train[], tasks: Task[]): AggregatedCell[] {
  const cells: AggregatedCell[] = [];
  const cellMap = new Map<string, AggregatedCell>();

  // Initialize all cells
  for (let trainIndex = 0; trainIndex < trains.length; trainIndex++) {
    for (let quarterIndex = 0; quarterIndex < TIME_RANGE.quarters; quarterIndex++) {
      const key = `${trainIndex}-${quarterIndex}`;
      const cell: AggregatedCell = {
        trainIndex,
        periodIndex: quarterIndex,
        totalTasks: 0,
        totalManHours: 0,
        totalCostAed: 0,
        tasksByType: { pm1: 0, pm2: 0, pm3: 0, overhaul: 0, corrective: 0 },
        hasOverhaul: false,
        utilizationPercent: 0,
      };
      cellMap.set(key, cell);
    }
  }

  // Aggregate tasks
  for (const task of tasks) {
    const quarterIndex = getQuarterIndex(task.startDate);
    if (quarterIndex < 0 || quarterIndex >= TIME_RANGE.quarters) continue;

    const key = `${task.trainIndex}-${quarterIndex}`;
    const cell = cellMap.get(key);
    if (!cell) continue;

    cell.totalTasks++;
    cell.totalManHours += task.manHours;
    cell.totalCostAed += task.costAed;
    cell.tasksByType[task.type]++;
    if (task.type === 'overhaul') {
      cell.hasOverhaul = true;
    }
  }

  // Calculate utilization
  const maxManHoursPerQuarter = RESOURCES.max_manhours_per_month * 3; // 6000
  for (const cell of cellMap.values()) {
    cell.utilizationPercent = Math.min(100, (cell.totalManHours / maxManHoursPerQuarter) * 100);
    cells.push(cell);
  }

  return cells;
}

function aggregateByMonth(trains: Train[], tasks: Task[]): AggregatedCell[] {
  const cells: AggregatedCell[] = [];
  const cellMap = new Map<string, AggregatedCell>();

  // Initialize all cells
  for (let trainIndex = 0; trainIndex < trains.length; trainIndex++) {
    for (let monthIndex = 0; monthIndex < TIME_RANGE.months; monthIndex++) {
      const key = `${trainIndex}-${monthIndex}`;
      const cell: AggregatedCell = {
        trainIndex,
        periodIndex: monthIndex,
        totalTasks: 0,
        totalManHours: 0,
        totalCostAed: 0,
        tasksByType: { pm1: 0, pm2: 0, pm3: 0, overhaul: 0, corrective: 0 },
        hasOverhaul: false,
        utilizationPercent: 0,
      };
      cellMap.set(key, cell);
    }
  }

  // Aggregate tasks
  for (const task of tasks) {
    const monthIndex = getMonthIndex(task.startDate);
    if (monthIndex < 0 || monthIndex >= TIME_RANGE.months) continue;

    const key = `${task.trainIndex}-${monthIndex}`;
    const cell = cellMap.get(key);
    if (!cell) continue;

    cell.totalTasks++;
    cell.totalManHours += task.manHours;
    cell.totalCostAed += task.costAed;
    cell.tasksByType[task.type]++;
    if (task.type === 'overhaul') {
      cell.hasOverhaul = true;
    }
  }

  // Calculate utilization
  const maxManHoursPerMonth = RESOURCES.max_manhours_per_month; // 2000
  for (const cell of cellMap.values()) {
    cell.utilizationPercent = Math.min(100, (cell.totalManHours / maxManHoursPerMonth) * 100);
    cells.push(cell);
  }

  return cells;
}

// =============================================================================
// MAIN GENERATOR
// =============================================================================

let cachedData: MockData | null = null;

export function generateMockData(forceRegenerate: boolean = false): MockData {
  if (cachedData && !forceRegenerate) {
    return cachedData;
  }

  console.time('generateMockData');
  resetSeed(12345);

  // Generate trains
  const trains = generateTrains();
  console.log(`Generated ${trains.length} trains`);

  // Generate tasks for each train
  const taskIdCounter = { value: 1 };
  const allTasks: Task[] = [];

  for (const train of trains) {
    const trainTasks = generateTasksForTrain(train, taskIdCounter);
    allTasks.push(...trainTasks);
  }

  // Sort tasks by date
  allTasks.sort((a, b) => a.startDate.getTime() - b.startDate.getTime());
  console.log(`Generated ${allTasks.length} tasks`);

  // Aggregate data
  const aggregatedByQuarter = aggregateByQuarter(trains, allTasks);
  const aggregatedByMonth = aggregateByMonth(trains, allTasks);
  console.log(`Aggregated: ${aggregatedByQuarter.length} quarterly cells, ${aggregatedByMonth.length} monthly cells`);

  // Calculate stats
  const conflictCount = allTasks.filter(t => t.hasConflict).length;
  const totalManHours = allTasks.reduce((sum, t) => sum + t.manHours, 0);
  const totalCostAed = allTasks.reduce((sum, t) => sum + t.costAed, 0);

  const data: MockData = {
    trains,
    tasks: allTasks,
    aggregatedByQuarter,
    aggregatedByMonth,
    stats: {
      totalTrains: trains.length,
      totalTasks: allTasks.length,
      totalManHours,
      totalCostAed,
      avgTasksPerTrain: Math.round(allTasks.length / trains.length),
      conflictCount,
    },
  };

  console.timeEnd('generateMockData');
  console.log('Stats:', data.stats);

  cachedData = data;
  return data;
}

// =============================================================================
// QUERY UTILITIES
// =============================================================================

export function getTasksInRange(data: MockData, startDate: Date, endDate: Date): Task[] {
  return data.tasks.filter(
    t => t.startDate >= startDate && t.startDate <= endDate
  );
}

export function getTasksForTrain(data: MockData, trainId: string): Task[] {
  return data.tasks.filter(t => t.trainId === trainId);
}

export function getTasksForTrainInRange(
  data: MockData,
  trainId: string,
  startDate: Date,
  endDate: Date
): Task[] {
  return data.tasks.filter(
    t => t.trainId === trainId && t.startDate >= startDate && t.startDate <= endDate
  );
}

export function getAggregatedCellsForViewport(
  cells: AggregatedCell[],
  trainIndexStart: number,
  trainIndexEnd: number,
  periodIndexStart: number,
  periodIndexEnd: number
): AggregatedCell[] {
  return cells.filter(
    c =>
      c.trainIndex >= trainIndexStart &&
      c.trainIndex <= trainIndexEnd &&
      c.periodIndex >= periodIndexStart &&
      c.periodIndex <= periodIndexEnd
  );
}

// Export for direct import
export { FLEETS, MAINTENANCE_TYPES, TIME_RANGE, RESOURCES, MILEAGE, COLORS } from './mock-config';

