    42→// =============================================================================
    43→// TYPES
    44→// =============================================================================
    45→
    46→export interface FractalCanvasCompleteProps {
    47→  /** Width of the viewport */
    48→  width: number;
    49→  /** Height of the viewport */
    50→  height: number;
    51→  /** Initial zoom level */
    52→  initialZoom?: number;
    53→  /** Show constraint deck */
    54→  showConstraintDeck?: boolean;
    55→  /** Show time scrubber */
    56→  showTimeScrubber?: boolean;
    57→  /** Enable keyboard shortcuts */
    58→  enableKeyboard?: boolean;
    59→}
    60→
    61→type LODLevel = 'strategic' | 'tactical' | 'operational' | 'execution';
    62→
    63→interface ViewState {
    64→  target: [number, number, number];
    65→  zoom: number;
    66→}
    67→
    68→// =============================================================================
    69→// CONSTANTS
    70→// =============================================================================
    71→
    72→const LOD_THRESHOLDS = {
    73→  strategic: { max: 0.3 },
    74→  tactical: { min: 0.3, max: 1.0 },
    75→  operational: { min: 1.0, max: 3.0 },
    76→  execution: { min: 3.0 },
    77→};
    78→
    79→const TRANSITION_RANGE = 0.15;
    80→
    81→// Layer pixel constants
    82→const STRATEGIC_CELL_WIDTH = 30;
    83→const STRATEGIC_CELL_HEIGHT = 8;
    84→const TACTICAL_CELL_WIDTH = 20;
    85→const TACTICAL_CELL_HEIGHT = 16;
    86→const OPERATIONAL_PX_PER_DAY = 8;
    87→const OPERATIONAL_PX_PER_TRAIN = 28;
    88→
    89→// UI constants
    90→const NAVBAR_HEIGHT = 50;
    91→const SIDEBAR_WIDTH = 120;
    92→const TIMELINE_HEIGHT = 48;
    93→const SCRUBBER_HEIGHT = 100;
    94→const CONSTRAINT_HEIGHT = 80;
    95→
    96→// =============================================================================
    97→// HELPERS
    98→// =============================================================================
    99→
   100→function getLODLevel(zoom: number): LODLevel {
   101→  if (zoom < LOD_THRESHOLDS.strategic.max) return 'strategic';
   102→  if (zoom < LOD_THRESHOLDS.tactical.max) return 'tactical';
   103→  if (zoom < LOD_THRESHOLDS.operational.max) return 'operational';
   104→  return 'execution';
   105→}
   106→
   107→function getLODOpacity(zoom: number, level: LODLevel): number {
   108→  const thresholds = LOD_THRESHOLDS[level];
   109→
   110→  if (level === 'strategic') {
   111→    if (zoom <= thresholds.max - TRANSITION_RANGE) return 1;
   112→    if (zoom >= thresholds.max) return 0;
   113→    return 1 - (zoom - (thresholds.max - TRANSITION_RANGE)) / TRANSITION_RANGE;
   114→  }
   115→
   116→  if (level === 'tactical') {
   117→    const fadeIn = zoom < thresholds.min! + TRANSITION_RANGE
   118→      ? (zoom - thresholds.min!) / TRANSITION_RANGE
   119→      : 1;
   120→    const fadeOut = zoom > thresholds.max - TRANSITION_RANGE
   121→      ? 1 - (zoom - (thresholds.max - TRANSITION_RANGE)) / TRANSITION_RANGE
   122→      : 1;
   123→    return Math.max(0, Math.min(1, Math.min(fadeIn, fadeOut)));
   124→  }
   125→
   126→  if (level === 'operational') {
   127→    const fadeIn = zoom < thresholds.min! + TRANSITION_RANGE
   128→      ? (zoom - thresholds.min!) / TRANSITION_RANGE
   129→      : 1;
   130→    const fadeOut = zoom > thresholds.max - TRANSITION_RANGE
   131→      ? 1 - (zoom - (thresholds.max - TRANSITION_RANGE)) / TRANSITION_RANGE
   132→      : 1;
   133→    return Math.max(0, Math.min(1, Math.min(fadeIn, fadeOut)));
   134→  }
   135→
   136→  if (level === 'execution') {
   137→    if (zoom >= thresholds.min! + TRANSITION_RANGE) return 1;
   138→    if (zoom <= thresholds.min!) return 0;
   139→    return (zoom - thresholds.min!) / TRANSITION_RANGE;
   140→  }
   141→
   142→  return 0;
   143→}
   144→
   145→function daysBetween(start: Date, end: Date): number {
   146→  return Math.floor((end.getTime() - start.getTime()) / (1000 * 60 * 60 * 24));
   147→}
   148→
   149→function hexToRgba(hex: string, alpha: number = 255): [number, number, number, number] {
   150→  const result = /^#?([a-f\d]{2})([a-f\d]{2})([a-f\d]{2})$/i.exec(hex);
   151→  if (result) {
   152→    return [
   153→      parseInt(result[1], 16),
   154→      parseInt(result[2], 16),
   155→      parseInt(result[3], 16),
   156→      alpha,
   157→    ];
   158→  }
   159→  return [128, 128, 128, alpha];
   160→}
   161→
   162→function getLODColor(level: LODLevel): string {
   163→  switch (level) {
   164→    case 'strategic': return '#3b82f6';
   165→    case 'tactical': return '#f59e0b';
   166→    case 'operational': return '#22c55e';
   167→    case 'execution': return '#ef4444';
   168→  }
   169→}
   170→
   171→function getLODIntent(level: LODLevel): Intent {
   172→  switch (level) {
   173→    case 'strategic': return Intent.PRIMARY;
   174→    case 'tactical': return Intent.WARNING;
   175→    case 'operational': return Intent.SUCCESS;
   176→    case 'execution': return Intent.DANGER;
   177→  }
   178→}
   179→
   180→// =============================================================================
   181→// COMPONENT
   182→// =============================================================================
   183→
   184→export const FractalCanvasComplete: React.FC<FractalCanvasCompleteProps> = ({
   185→  width,
   186→  height,
   187→  initialZoom = 0.5,
   188→  showConstraintDeck = true,
   189→  showTimeScrubber = true,
   190→  enableKeyboard = true,
   191→}) => {
   192→  // Generate mock data
   193→  const mockData = useMemo(() => generateMockData(), []);
   194→
   195→  // Generate density data for time scrubber
   196→  const densityData = useMemo(
   197→    () => generateDensityData(TIME_RANGE.start, TIME_RANGE.end, 4),
   198→    []
   199→  );
   200→
   201→  // State
   202→  const [zoom, setZoom] = useState(initialZoom);
   203→  const [cameraX, setCameraX] = useState(0);
   204→  const [cameraY, setCameraY] = useState(0);
   205→  const [hoveredTask, setHoveredTask] = useState<Task | null>(null);
   206→  const [constraintDeckCollapsed, setConstraintDeckCollapsed] = useState(false);
   207→  const [timeRangeStart, setTimeRangeStart] = useState(TIME_RANGE.start.getTime());
   208→  const [timeRangeEnd, setTimeRangeEnd] = useState(
   209→    TIME_RANGE.start.getTime() + 2 * 365 * 24 * 60 * 60 * 1000 // 2 years
   210→  );
   211→
   212→  // Refs
   213→  const containerRef = useRef<HTMLDivElement>(null);
   214→
   215→  // Current LOD level
   216→  const currentLOD = getLODLevel(zoom);
   217→
   218→  // Calculate opacities
   219→  const opacities = useMemo(() => ({
   220→    strategic: getLODOpacity(zoom, 'strategic'),
   221→    tactical: getLODOpacity(zoom, 'tactical'),
   222→    operational: getLODOpacity(zoom, 'operational'),
   223→    execution: getLODOpacity(zoom, 'execution'),
   224→  }), [zoom]);
   225→
   226→  // Calculate layout dimensions
   227→  const canvasHeight = useMemo(() => {
   228→    let h = height - NAVBAR_HEIGHT - TIMELINE_HEIGHT;
   229→    if (showTimeScrubber) h -= SCRUBBER_HEIGHT;
   230→    if (showConstraintDeck && !constraintDeckCollapsed) h -= CONSTRAINT_HEIGHT;
   231→    else if (showConstraintDeck) h -= 40; // Just header
   232→    return Math.max(200, h);
   233→  }, [height, showTimeScrubber, showConstraintDeck, constraintDeckCollapsed]);
   234→
   235→  const canvasWidth = width - SIDEBAR_WIDTH;
   236→
   237→  // World dimensions
   238→  const worldDimensions = useMemo(() => {
   239→    const totalDays = TIME_RANGE.years * 365;
   240→    const trainCount = mockData.trains.length;
   241→
   242→    return {
   243→      strategic: {
   244→        width: (TIME_RANGE.years * 4) * STRATEGIC_CELL_WIDTH,
   245→        height: trainCount * STRATEGIC_CELL_HEIGHT,
   246→      },
   247→      tactical: {
   248→        width: (TIME_RANGE.years * 12) * TACTICAL_CELL_WIDTH,
   249→        height: trainCount * TACTICAL_CELL_HEIGHT,
   250→      },
   251→      operational: {
   252→        width: totalDays * OPERATIONAL_PX_PER_DAY,
   253→        height: trainCount * OPERATIONAL_PX_PER_TRAIN,
   254→      },
   255→    };
   256→  }, [mockData.trains.length]);
   257→
   258→  // Strategic layer
   259→  const strategicLayers = useMemo(() => {
   260→    if (opacities.strategic <= 0) return [];
   261→
   262→    return [
   263→      new SolidPolygonLayer<AggregatedCell>({
   264→        id: 'strategic-heatmap',
   265→        data: mockData.aggregatedByQuarter,
   266→        getPolygon: (d) => {
   267→          const x = d.periodIndex * STRATEGIC_CELL_WIDTH;
   268→          const y = d.trainIndex * STRATEGIC_CELL_HEIGHT;
   269→          return [
   270→            [x, y],
   271→            [x + STRATEGIC_CELL_WIDTH - 1, y],
   272→            [x + STRATEGIC_CELL_WIDTH - 1, y + STRATEGIC_CELL_HEIGHT - 1],
   273→            [x, y + STRATEGIC_CELL_HEIGHT - 1],
   274→          ];
   275→        },
   276→        getFillColor: (d) => {
   277→          const intensity = Math.min(1, d.utilizationPercent / 100);
   278→          if (intensity < 0.5) {
   279→            const t = intensity * 2;
   280→            return [255, Math.round(243 - t * 50), Math.round(196 - t * 100), 255 * opacities.strategic];
   281→          } else {
   282→            const t = (intensity - 0.5) * 2;
   283→            return [255, Math.round(193 - t * 100), Math.round(96 - t * 96), 255 * opacities.strategic];
   284→          }
   285→        },
   286→        pickable: true,
   287→        opacity: opacities.strategic,
   288→        updateTriggers: {
   289→          getFillColor: [opacities.strategic],
   290→        },
   291→      }),
   292→    ];
   293→  }, [mockData.aggregatedByQuarter, opacities.strategic]);
   294→
   295→  // Tactical layer
   296→  const tacticalLayers = useMemo(() => {
   297→    if (opacities.tactical <= 0) return [];
   298→
   299→    return [
   300→      new SolidPolygonLayer<AggregatedCell>({
   301→        id: 'tactical-bars',
   302→        data: mockData.aggregatedByMonth,
   303→        getPolygon: (d) => {
   304→          const x = d.periodIndex * TACTICAL_CELL_WIDTH;
   305→          const y = d.trainIndex * TACTICAL_CELL_HEIGHT;
   306→          const barHeight = (d.utilizationPercent / 100) * (TACTICAL_CELL_HEIGHT - 2);
   307→          return [
   308→            [x + 1, y + TACTICAL_CELL_HEIGHT - 1 - barHeight],
   309→            [x + TACTICAL_CELL_WIDTH - 2, y + TACTICAL_CELL_HEIGHT - 1 - barHeight],
   310→            [x + TACTICAL_CELL_WIDTH - 2, y + TACTICAL_CELL_HEIGHT - 1],
   311→            [x + 1, y + TACTICAL_CELL_HEIGHT - 1],
   312→          ];
   313→        },
   314→        getFillColor: (d) => {
   315→          if (d.hasConflict) return [239, 68, 68, 255 * opacities.tactical];
   316→          const intensity = Math.min(1, d.utilizationPercent / 100);
   317→          if (intensity > 0.8) return [239, 68, 68, 255 * opacities.tactical];
   318→          if (intensity > 0.6) return [251, 191, 36, 255 * opacities.tactical];
   319→          return [34, 197, 94, 255 * opacities.tactical];
   320→        },
   321→        pickable: true,
   322→        opacity: opacities.tactical,
   323→        updateTriggers: {
   324→          getFillColor: [opacities.tactical],
   325→        },
   326→      }),
   327→    ];
   328→  }, [mockData.aggregatedByMonth, opacities.tactical]);
   329→
   330→  // Operational layer
   331→  const operationalLayers = useMemo(() => {
   332→    if (opacities.operational <= 0) return [];
   333→
   334→    interface TaskPolygon {
   335→      polygon: [number, number][];
   336→      task: Task;
   337→      color: [number, number, number, number];
   338→    }
   339→
   340→    const taskPolygons: TaskPolygon[] = mockData.tasks.map((task) => {
   341→      const startDay = daysBetween(TIME_RANGE.start, task.startDate);
   342→      const duration = Math.max(1, daysBetween(task.startDate, task.endDate));
   343→
   344→      const x = startDay * OPERATIONAL_PX_PER_DAY;
   345→      const y = task.trainIndex * OPERATIONAL_PX_PER_TRAIN + 4;
   346→      const w = duration * OPERATIONAL_PX_PER_DAY - 1;
   347→      const h = 20;
   348→
   349→      const mt = MAINTENANCE_TYPE_MAP.get(task.type);
   350→      const baseColor = mt?.color ?? COLORS.task.default;
   351→
   352→      return {
   353→        polygon: [
   354→          [x, y],
   355→          [x + w, y],
   356→          [x + w, y + h],
   357→          [x, y + h],
   358→        ],
   359→        task,
   360→        color: hexToRgba(baseColor, 255 * opacities.operational),
   361→      };
   362→    });
   363→
   364→    return [
   365→      // Background rows
   366→      new SolidPolygonLayer<{ polygon: [number, number][]; index: number }>({
   367→        id: 'operational-grid',
   368→        data: mockData.trains.map((_, i) => ({
   369→          polygon: [
   370→            [0, i * OPERATIONAL_PX_PER_TRAIN],
   371→            [worldDimensions.operational.width, i * OPERATIONAL_PX_PER_TRAIN],
   372→            [worldDimensions.operational.width, (i + 1) * OPERATIONAL_PX_PER_TRAIN - 1],
   373→            [0, (i + 1) * OPERATIONAL_PX_PER_TRAIN - 1],
   374→          ],
   375→          index: i,
   376→        })),
   377→        getPolygon: (d) => d.polygon,
   378→        getFillColor: (d) => d.index % 2 === 0
   379→          ? [250, 250, 250, 255 * opacities.operational]
   380→          : [245, 245, 245, 255 * opacities.operational],
   381→        pickable: false,
   382→        opacity: opacities.operational * 0.8,
   383→      }),
   384→      // Task bars
   385→      new SolidPolygonLayer<TaskPolygon>({
   386→        id: 'operational-tasks',
   387→        data: taskPolygons,
   388→        getPolygon: (d) => d.polygon,
   389→        getFillColor: (d) => {
   390→          if (d.task.hasConflict) return [239, 68, 68, 255 * opacities.operational];
   391→          return d.color;
   392→        },
   393→        pickable: true,
   394→        opacity: opacities.operational,
   395→        updateTriggers: {
   396→          getFillColor: [opacities.operational],
   397→        },
   398→      }),
   399→    ];
   400→  }, [mockData.tasks, mockData.trains.length, worldDimensions.operational.width, opacities.operational]);
   401→
   402→  // All layers
   403→  const layers = useMemo(() => [
   404→    ...strategicLayers,
   405→    ...tacticalLayers,
   406→    ...operationalLayers,
   407→  ], [strategicLayers, tacticalLayers, operationalLayers]);
   408→
   409→  // View state
   410→  const viewState: ViewState = useMemo(() => {
   411→    let targetX = cameraX;
   412→    let targetY = cameraY;
   413→
   414→    if (currentLOD === 'strategic') {
   415→      targetX = cameraX * STRATEGIC_CELL_WIDTH / OPERATIONAL_PX_PER_DAY * 90;
   416→      targetY = cameraY * STRATEGIC_CELL_HEIGHT;
   417→    } else if (currentLOD === 'tactical') {
   418→      targetX = cameraX * TACTICAL_CELL_WIDTH / OPERATIONAL_PX_PER_DAY * 30;
   419→      targetY = cameraY * TACTICAL_CELL_HEIGHT;
   420→    } else {
   421→      targetX = cameraX * OPERATIONAL_PX_PER_DAY;
   422→      targetY = cameraY * OPERATIONAL_PX_PER_TRAIN;
   423→    }
   424→
   425→    return {
   426→      target: [targetX + canvasWidth / 2, targetY + canvasHeight / 2, 0],
   427→      zoom: Math.log2(zoom),
   428→    };
   429→  }, [cameraX, cameraY, zoom, canvasWidth, canvasHeight, currentLOD]);
   430→
   431→  // Handlers
   432→  const handleZoomChange = useCallback((delta: number) => {
   433→    setZoom((z) => Math.max(0.1, Math.min(5, z + delta)));
   434→  }, []);
   435→
   436→  const handleTimeRangeChange = useCallback((start: number, end: number) => {
   437→    setTimeRangeStart(start);
   438→    setTimeRangeEnd(end);
   439→    // Sync camera X to start of selected range
   440→    const dayOffset = daysBetween(TIME_RANGE.start, new Date(start));
   441→    setCameraX(dayOffset);
   442→  }, []);
   443→
   444→  // Keyboard shortcuts
   445→  useEffect(() => {
   446→    if (!enableKeyboard) return;
   447→
   448→    const handleKeyDown = (e: KeyboardEvent) => {
   449→      switch (e.key) {
   450→        case '+':
   451→        case '=':
   452→          handleZoomChange(0.1);
   453→          break;
   454→        case '-':
   455→          handleZoomChange(-0.1);
   456→          break;
   457→        case '1':
   458→          setZoom(0.2);
   459→          break;
   460→        case '2':
   461→          setZoom(0.6);
   462→          break;
   463→        case '3':
   464→          setZoom(1.8);
   465→          break;
   466→        case '4':
   467→          setZoom(4.0);
   468→          break;
   469→        case 'Home':
   470→          setZoom(initialZoom);
   471→          setCameraX(0);
   472→          setCameraY(0);
   473→          break;
   474→      }
   475→    };
   476→
   477→    window.addEventListener('keydown', handleKeyDown);
   478→    return () => window.removeEventListener('keydown', handleKeyDown);
   479→  }, [enableKeyboard, handleZoomChange, initialZoom]);
   480→
   481→  // Visible trains for sidebar
   482→  const visibleTrains = useMemo(() => {
   483→    const rowHeight = currentLOD === 'strategic' ? STRATEGIC_CELL_HEIGHT * zoom
   484→      : currentLOD === 'tactical' ? TACTICAL_CELL_HEIGHT * zoom
   485→      : OPERATIONAL_PX_PER_TRAIN * zoom;
   486→    const startIndex = Math.max(0, Math.floor(cameraY));
   487→    const visibleCount = Math.ceil(canvasHeight / Math.max(rowHeight, 20)) + 2;
   488→    return mockData.trains.slice(startIndex, startIndex + visibleCount);
   489→  }, [cameraY, canvasHeight, zoom, currentLOD, mockData.trains]);
   490→
   491→  // View
   492→  const views = new OrthographicView({
   493→    id: 'fractal-view',
   494→    flipY: false,
   495→    controller: true,
   496→  });
   497→
   498→  // Timeline granularity
   499→  const timelineGranularity = getGranularityForZoom(zoom);
   500→
   501→  return (
   502→    <div
   503→      ref={containerRef}
   504→      style={{ width, height, position: 'relative', background: '#f4f4f5', overflow: 'hidden' }}
   505→    >
   506→      {/* Navbar */}
   507→      <Navbar style={{ height: NAVBAR_HEIGHT }}>
   508→        <NavbarGroup align={Alignment.LEFT}>
   509→          <Icon icon="train" size={18} style={{ marginRight: 8 }} />
   510→          <NavbarHeading style={{ fontSize: 15, fontWeight: 600 }}>
   511→            MMS Fractal Canvas
   512→          </NavbarHeading>
   513→          <NavbarDivider />
   514→          <Tag
   515→            intent={getLODIntent(currentLOD)}
   516→            large
   517→            style={{ minWidth: 100, textAlign: 'center' }}
   518→          >
   519→            {currentLOD.toUpperCase()}
   520→          </Tag>
   521→          <span style={{ marginLeft: 16, fontSize: 12, color: '#64748b' }}>
   522→            {mockData.stats.totalTasks.toLocaleString()} tasks | {mockData.stats.totalTrains} trains
   523→          </span>
   524→        </NavbarGroup>
   525→        <NavbarGroup align={Alignment.RIGHT}>
   526→          <div style={{ display: 'flex', alignItems: 'center', gap: 16 }}>
   527→            <div style={{ fontSize: 12 }}>
   528→              <span style={{ color: '#64748b' }}>Zoom: </span>
   529→              <span style={{ fontWeight: 600 }}>{zoom.toFixed(2)}x</span>
   530→            </div>
   531→            <ButtonGroup>
   532→              <Tooltip content="Strategic (1)">
   533→                <Button
   534→                  small
   535→                  intent={currentLOD === 'strategic' ? Intent.PRIMARY : Intent.NONE}
   536→                  onClick={() => setZoom(0.2)}
   537→                >
   538→                  S
   539→                </Button>
   540→              </Tooltip>
   541→              <Tooltip content="Tactical (2)">
   542→                <Button
   543→                  small
   544→                  intent={currentLOD === 'tactical' ? Intent.WARNING : Intent.NONE}
   545→                  onClick={() => setZoom(0.6)}
   546→                >
   547→                  T
   548→                </Button>
   549→              </Tooltip>
   550→              <Tooltip content="Operational (3)">
   551→                <Button
   552→                  small
   553→                  intent={currentLOD === 'operational' ? Intent.SUCCESS : Intent.NONE}
   554→                  onClick={() => setZoom(1.8)}
   555→                >
   556→                  O
   557→                </Button>
   558→              </Tooltip>
   559→              <Tooltip content="Execution (4)">
   560→                <Button
   561→                  small
   562→                  intent={currentLOD === 'execution' ? Intent.DANGER : Intent.NONE}
   563→                  onClick={() => setZoom(4.0)}
   564→                >
   565→                  E
   566→                </Button>
   567→              </Tooltip>
   568→            </ButtonGroup>
   569→            <ButtonGroup>
   570→              <Button icon="minus" small onClick={() => handleZoomChange(-0.1)} />
   571→              <Button icon="plus" small onClick={() => handleZoomChange(0.1)} />
   572→              <Button icon="home" small onClick={() => {
   573→                setZoom(initialZoom);
   574→                setCameraX(0);
   575→                setCameraY(0);
   576→              }} />
   577→            </ButtonGroup>
   578→          </div>
   579→        </NavbarGroup>
   580→      </Navbar>
   581→
   582→      {/* Main content */}
   583→      <div style={{ display: 'flex', height: height - NAVBAR_HEIGHT }}>
   584→        {/* Sidebar */}
   585→        <Card
   586→          style={{
   587→            width: SIDEBAR_WIDTH,
   588→            height: '100%',
   589→            borderRadius: 0,
   590→            padding: 0,
   591→            overflow: 'hidden',
   592→            borderRight: '1px solid #e2e8f0',
   593→          }}
   594→        >
   595→          <div
   596→            style={{
   597→              padding: '8px 12px',
   598→              borderBottom: '1px solid #e2e8f0',
   599→              fontWeight: 600,
   600→              fontSize: 12,
   601→              background: '#f8fafc',
   602→              height: TIMELINE_HEIGHT,
   603→              display: 'flex',
   604→              alignItems: 'center',
   605→            }}
   606→          >
   607→            <Icon icon="train" size={12} style={{ marginRight: 6 }} />
   608→            Trains ({mockData.trains.length})
   609→          </div>
   610→          <div style={{ overflowY: 'auto', height: canvasHeight }}>
   611→            {visibleTrains.map((train) => (
   612→              <div
   613→                key={train.id}
   614→                style={{
   615→                  padding: '6px 12px',
   616→                  borderBottom: '1px solid #f1f5f9',
   617→                  fontSize: 10,
   618→                  background: train.index % 2 === 0 ? '#fff' : '#fafafa',
   619→                }}
   620→              >
   621→                <div style={{ fontWeight: 600, marginBottom: 2 }}>{train.name}</div>
   622→                <Tag
   623→                  minimal
   624→                  intent={train.fleetId === 'kinki' ? Intent.SUCCESS : Intent.PRIMARY}
   625→                  style={{ fontSize: 9 }}
   626→                >
   627→                  {train.fleetId === 'kinki' ? 'KNK' : 'ALT'}
   628→                </Tag>
   629→              </div>
   630→            ))}
   631→          </div>
   632→        </Card>
   633→
   634→        {/* Canvas area */}
   635→        <div style={{ flex: 1, display: 'flex', flexDirection: 'column' }}>
   636→          {/* Timeline Header */}
   637→          <TimelineHeader
   638→            startDate={TIME_RANGE.start}
   639→            endDate={TIME_RANGE.end}
   640→            width={canvasWidth}
   641→            height={TIMELINE_HEIGHT}
   642→            granularity={timelineGranularity}
   643→            pxPerDay={OPERATIONAL_PX_PER_DAY * zoom}
   644→            offsetX={cameraX * OPERATIONAL_PX_PER_DAY * zoom}
   645→          />
   646→
   647→          {/* deck.gl Canvas */}
   648→          <div style={{ flex: 1, position: 'relative' }}>
   649→            {/* Execution overlay (HTML) */}
   650→            {opacities.execution > 0 && (
   651→              <ExecutionOverlay
   652→                tasks={mockData.tasks}
