   658→                height={canvasHeight}
   659→                opacity={opacities.execution}
   660→              />
   661→            )}
   662→
   663→            {/* deck.gl layers */}
   664→            {(opacities.strategic > 0 || opacities.tactical > 0 || opacities.operational > 0) && (
   665→              <DeckGL
   666→                width={canvasWidth}
   667→                height={canvasHeight}
   668→                views={views}
   669→                viewState={viewState}
   670→                layers={layers}
   671→                getCursor={() => 'grab'}
   672→                style={{ opacity: Math.max(opacities.strategic, opacities.tactical, opacities.operational) }}
   673→              />
   674→            )}
   675→
   676→            {/* LOD indicator */}
   677→            <div
   678→              style={{
   679→                position: 'absolute',
   680→                bottom: 16,
   681→                right: 16,
   682→                background: 'white',
