   686→                fontSize: 11,
   687→              }}
   688→            >
   689→              <div style={{ fontWeight: 600, marginBottom: 8 }}>Layer Visibility</div>
   690→              {(['strategic', 'tactical', 'operational', 'execution'] as LODLevel[]).map((level) => (
   691→                <div key={level} style={{ display: 'flex', alignItems: 'center', gap: 8, marginBottom: 4 }}>
   692→                  <div
