   696→                      background: `linear-gradient(to right, ${getLODColor(level)} ${opacities[level] * 100}%, #e5e7eb ${opacities[level] * 100}%)`,
   697→                      borderRadius: 3,
   698→                    }}
   699→                  />
   700→                  <span>{level} ({Math.round(opacities[level] * 100)}%)</span>
   701→                </div>
   702→              ))}
   703→            </div>
   704→
   705→            {/* Zoom slider */}
   706→            <Card
   707→              style={{
   708→                position: 'absolute',
   709→                bottom: 16,
   710→                left: 16,
   711→                padding: 12,
   712→                width: 200,
   713→              }}
   714→            >
