   726→              />
   727→              <div style={{ fontSize: 9, color: '#666', marginTop: 8 }}>
   728→                <div>S: &lt;0.3x | T: 0.3-1.0x</div>
   729→                <div>O: 1.0-3.0x | E: &gt;3.0x</div>
   730→              </div>
   731→            </Card>
   732→          </div>
   733→
   734→          {/* Time Scrubber */}
   735→          {showTimeScrubber && (
   736→            <TimeScrubber
   737→              data={densityData}
