   756→            />
   757→          )}
   758→        </div>
   759→      </div>
   760→    </div>
   761→  );
   762→};
   763→
   764→// =============================================================================
   765→// EXECUTION OVERLAY
   766→// =============================================================================
   767→
   768→interface ExecutionOverlayProps {
   769→  tasks: Task[];
   770→  trains: Train[];
   771→  cameraX: number;
   772→  cameraY: number;
   773→  zoom: number;
   774→  width: number;
   775→  height: number;
   776→  opacity: number;
   777→}
   778→
   779→const ExecutionOverlay: React.FC<ExecutionOverlayProps> = ({
   780→  tasks,
   781→  trains,
   782→  cameraX,
   783→  cameraY,
   784→  zoom,
   785→  width,
   786→  height,
   787→  opacity,
   788→}) => {
   789→  const ROW_HEIGHT = 80;
   790→  const EXEC_PX_PER_DAY = 80;
   791→
   792→  const visibleTasks = useMemo(() => {
   793→    const startTrain = Math.max(0, Math.floor(cameraY));
   794→    const endTrain = Math.min(trains.length - 1, Math.ceil(cameraY + height / ROW_HEIGHT));
   795→    return tasks
   796→      .filter((task) => task.trainIndex >= startTrain && task.trainIndex <= endTrain)
   797→      .slice(0, 50);
   798→  }, [tasks, trains.length, cameraY, height]);
   799→
   800→  const earliestTaskDay = useMemo(() => {
   801→    if (visibleTasks.length === 0) return 0;
   802→    return Math.min(...visibleTasks.map(t => daysBetween(TIME_RANGE.start, t.startDate)));
   803→  }, [visibleTasks]);
   804→
   805→  return (
   806→    <div
   807→      style={{
   808→        position: 'absolute',
   809→        top: 0,
   810→        left: 0,
   811→        width,
   812→        height,
   813→        overflow: 'hidden',
   814→        background: '#f8fafc',
   815→        opacity,
   816→        pointerEvents: opacity > 0.5 ? 'auto' : 'none',
   817→      }}
   818→    >
   819→      <div
   820→        style={{
   821→          position: 'absolute',
   822→          top: 0,
   823→          left: 0,
   824→          right: 0,
   825→          height: 40,
   826→          background: 'white',
   827→          borderBottom: '1px solid #e2e8f0',
   828→          display: 'flex',
   829→          alignItems: 'center',
   830→          paddingLeft: 16,
   831→          fontWeight: 600,
   832→          fontSize: 12,
   833→        }}
   834→      >
   835→        <Icon icon="calendar" size={14} style={{ marginRight: 8 }} />
   836→        Execution View - {visibleTasks.length} tasks visible
   837→      </div>
   838→
   839→      <div
   840→        style={{
   841→          position: 'absolute',
   842→          top: 40,
   843→          left: 0,
   844→          right: 0,
   845→          bottom: 0,
   846→          overflow: 'auto',
   847→        }}
   848→      >
   849→        {visibleTasks.map((task) => {
   850→          const startDay = daysBetween(TIME_RANGE.start, task.startDate);
   851→          const duration = Math.max(1, daysBetween(task.startDate, task.endDate));
   852→          const dayOffset = startDay - earliestTaskDay;
   853→
   854→          const x = 16 + dayOffset * EXEC_PX_PER_DAY;
   855→          const y = (task.trainIndex - Math.floor(cameraY)) * ROW_HEIGHT + 10;
   856→          const w = Math.max(duration * EXEC_PX_PER_DAY - 10, 150);
   857→
   858→          const mt = MAINTENANCE_TYPE_MAP.get(task.type);
   859→
   860→          return (
   861→            <Card
   862→              key={task.id}
   863→              interactive
   864→              elevation={1}
   865→              style={{
   866→                position: 'absolute',
   867→                left: x,
   868→                top: y,
   869→                width: w,
   870→                height: 60,
   871→                padding: 8,
   872→                borderLeft: `4px solid ${mt?.color ?? '#94a3b8'}`,
   873→              }}
   874→            >
   875→              <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start', marginBottom: 4 }}>
   876→                <div style={{ fontSize: 10, fontWeight: 600 }}>{task.name}</div>
   877→                <Tag
   878→                  minimal
   879→                  intent={
   880→                    task.status === 'completed' ? Intent.SUCCESS :
   881→                    task.status === 'in-progress' ? Intent.PRIMARY :
   882→                    task.status === 'overdue' ? Intent.DANGER :
   883→                    Intent.NONE
   884→                  }
   885→                  style={{ fontSize: 8 }}
   886→                >
   887→                  {task.status}
   888→                </Tag>
   889→              </div>
   890→              <div style={{ fontSize: 9, color: '#64748b' }}>
   891→                {task.durationHours}h | {task.manHours}mh | Pit {task.pitId}
   892→              </div>
   893→              {task.hasConflict && (
   894→                <Tag intent={Intent.DANGER} style={{ position: 'absolute', top: 4, right: 4, fontSize: 8 }}>!</Tag>
   895→              )}
   896→            </Card>
   897→          );
   898→        })}
   899→      </div>
   900→    </div>
   901→  );
   902→};
   903→
   904→export default FractalCanvasComplete;
