/**
 * FractalCanvasComplete Component
 *
 * The complete semantic zoom visualization integrating all components:
 * - 4 LOD layers (Strategic, Tactical, Operational, Execution)
 * - Timeline Header with adaptive granularity
 * - Time Scrubber with density visualization
 * - Constraint Deck with resource meters
 * - Sidebar with train list
 *
 * This is the "Single Pane of Glass" solution for railway maintenance planning.
 */

import React, { useMemo, useState, useCallback, useEffect, useRef } from 'react';
import {
  Card,
  Tag,
  Intent,
  Slider,
  Button,
  ButtonGroup,
  Navbar,
  NavbarGroup,
  NavbarHeading,
  NavbarDivider,
  Alignment,
  Icon,
  Tooltip,
} from '@blueprintjs/core';
import DeckGL from '@deck.gl/react';
import { OrthographicView } from '@deck.gl/core';
import { SolidPolygonLayer, PathLayer, TextLayer } from '@deck.gl/layers';
import type { PickingInfo } from '@deck.gl/core';

import type { Task, Train, AggregatedCell } from '../data/mock-generator';
import { generateMockData } from '../data/mock-generator';
import { MAINTENANCE_TYPE_MAP, TIME_RANGE, COLORS } from '../data/mock-config';
import { TimelineHeader, getGranularityForZoom } from '../02-Layers/Components/TimelineHeader';
import { ConstraintDeck, DEFAULT_CONSTRAINT_DECK_PROPS } from './ConstraintDeck';
import { TimeScrubber, generateDensityData } from './TimeScrubber';

// =============================================================================
// TYPES
// =============================================================================

export interface FractalCanvasCompleteProps {
  /** Width of the viewport */
  width: number;
  /** Height of the viewport */
  height: number;
  /** Initial zoom level */
  initialZoom?: number;
  /** Show constraint deck */
  showConstraintDeck?: boolean;
  /** Show time scrubber */
  showTimeScrubber?: boolean;
  /** Enable keyboard shortcuts */
  enableKeyboard?: boolean;
}

type LODLevel = 'strategic' | 'tactical' | 'operational' | 'execution';

interface ViewState {
  target: [number, number, number];
  zoom: number;
}

// =============================================================================
// CONSTANTS
// =============================================================================

const LOD_THRESHOLDS = {
  strategic: { max: 0.3 },
  tactical: { min: 0.3, max: 1.0 },
  operational: { min: 1.0, max: 3.0 },
  execution: { min: 3.0 },
};

const TRANSITION_RANGE = 0.15;

// Layer pixel constants
const STRATEGIC_CELL_WIDTH = 30;
const STRATEGIC_CELL_HEIGHT = 8;
const TACTICAL_CELL_WIDTH = 20;
const TACTICAL_CELL_HEIGHT = 16;
const OPERATIONAL_PX_PER_DAY = 8;
const OPERATIONAL_PX_PER_TRAIN = 28;

// UI constants
const NAVBAR_HEIGHT = 50;
const SIDEBAR_WIDTH = 120;
const TIMELINE_HEIGHT = 48;
const SCRUBBER_HEIGHT = 100;
const CONSTRAINT_HEIGHT = 80;

// =============================================================================
// HELPERS
// =============================================================================

function getLODLevel(zoom: number): LODLevel {
  if (zoom < LOD_THRESHOLDS.strategic.max) return 'strategic';
  if (zoom < LOD_THRESHOLDS.tactical.max) return 'tactical';
  if (zoom < LOD_THRESHOLDS.operational.max) return 'operational';
  return 'execution';
}

function getLODOpacity(zoom: number, level: LODLevel): number {
  const thresholds = LOD_THRESHOLDS[level];

  if (level === 'strategic') {
    if (zoom <= thresholds.max - TRANSITION_RANGE) return 1;
    if (zoom >= thresholds.max) return 0;
    return 1 - (zoom - (thresholds.max - TRANSITION_RANGE)) / TRANSITION_RANGE;
  }

  if (level === 'tactical') {
    const fadeIn = zoom < thresholds.min! + TRANSITION_RANGE
      ? (zoom - thresholds.min!) / TRANSITION_RANGE
      : 1;
    const fadeOut = zoom > thresholds.max - TRANSITION_RANGE
      ? 1 - (zoom - (thresholds.max - TRANSITION_RANGE)) / TRANSITION_RANGE
      : 1;
    return Math.max(0, Math.min(1, Math.min(fadeIn, fadeOut)));
  }

  if (level === 'operational') {
    const fadeIn = zoom < thresholds.min! + TRANSITION_RANGE
      ? (zoom - thresholds.min!) / TRANSITION_RANGE
      : 1;
    const fadeOut = zoom > thresholds.max - TRANSITION_RANGE
      ? 1 - (zoom - (thresholds.max - TRANSITION_RANGE)) / TRANSITION_RANGE
      : 1;
    return Math.max(0, Math.min(1, Math.min(fadeIn, fadeOut)));
  }

  if (level === 'execution') {
    if (zoom >= thresholds.min! + TRANSITION_RANGE) return 1;
    if (zoom <= thresholds.min!) return 0;
    return (zoom - thresholds.min!) / TRANSITION_RANGE;
  }

  return 0;
}

function daysBetween(start: Date, end: Date): number {
  return Math.floor((end.getTime() - start.getTime()) / (1000 * 60 * 60 * 24));
}

function hexToRgba(hex: string, alpha: number = 255): [number, number, number, number] {
  const result = /^#?([a-f\d]{2})([a-f\d]{2})([a-f\d]{2})$/i.exec(hex);
  if (result) {
    return [
      parseInt(result[1], 16),
      parseInt(result[2], 16),
      parseInt(result[3], 16),
      alpha,
    ];
  }
  return [128, 128, 128, alpha];
}

function getLODColor(level: LODLevel): string {
  switch (level) {
    case 'strategic': return '#3b82f6';
    case 'tactical': return '#f59e0b';
    case 'operational': return '#22c55e';
    case 'execution': return '#ef4444';
  }
}

function getLODIntent(level: LODLevel): Intent {
  switch (level) {
    case 'strategic': return Intent.PRIMARY;
    case 'tactical': return Intent.WARNING;
    case 'operational': return Intent.SUCCESS;
    case 'execution': return Intent.DANGER;
  }
}

// =============================================================================
// COMPONENT
// =============================================================================

export const FractalCanvasComplete: React.FC<FractalCanvasCompleteProps> = ({
  width,
  height,
  initialZoom = 0.5,
  showConstraintDeck = true,
  showTimeScrubber = true,
  enableKeyboard = true,
}) => {
  // Generate mock data
  const mockData = useMemo(() => generateMockData(), []);

  // Generate density data for time scrubber
  const densityData = useMemo(
    () => generateDensityData(TIME_RANGE.start, TIME_RANGE.end, 4),
    []
  );

  // State
  const [zoom, setZoom] = useState(initialZoom);
  const [cameraX, setCameraX] = useState(0);
  const [cameraY, setCameraY] = useState(0);
  const [hoveredTask, setHoveredTask] = useState<Task | null>(null);
  const [constraintDeckCollapsed, setConstraintDeckCollapsed] = useState(false);
  const [timeRangeStart, setTimeRangeStart] = useState(TIME_RANGE.start.getTime());
  const [timeRangeEnd, setTimeRangeEnd] = useState(
    TIME_RANGE.start.getTime() + 2 * 365 * 24 * 60 * 60 * 1000 // 2 years
  );

  // Refs
  const containerRef = useRef<HTMLDivElement>(null);

  // Current LOD level
  const currentLOD = getLODLevel(zoom);

  // Calculate opacities
  const opacities = useMemo(() => ({
    strategic: getLODOpacity(zoom, 'strategic'),
    tactical: getLODOpacity(zoom, 'tactical'),
    operational: getLODOpacity(zoom, 'operational'),
    execution: getLODOpacity(zoom, 'execution'),
  }), [zoom]);

  // Calculate layout dimensions
  const canvasHeight = useMemo(() => {
    let h = height - NAVBAR_HEIGHT - TIMELINE_HEIGHT;
    if (showTimeScrubber) h -= SCRUBBER_HEIGHT;
    if (showConstraintDeck && !constraintDeckCollapsed) h -= CONSTRAINT_HEIGHT;
    else if (showConstraintDeck) h -= 40; // Just header
    return Math.max(200, h);
  }, [height, showTimeScrubber, showConstraintDeck, constraintDeckCollapsed]);

  const canvasWidth = width - SIDEBAR_WIDTH;

  // World dimensions
  const worldDimensions = useMemo(() => {
    const totalDays = TIME_RANGE.years * 365;
    const trainCount = mockData.trains.length;

    return {
      strategic: {
        width: (TIME_RANGE.years * 4) * STRATEGIC_CELL_WIDTH,
        height: trainCount * STRATEGIC_CELL_HEIGHT,
      },
      tactical: {
        width: (TIME_RANGE.years * 12) * TACTICAL_CELL_WIDTH,
        height: trainCount * TACTICAL_CELL_HEIGHT,
      },
      operational: {
        width: totalDays * OPERATIONAL_PX_PER_DAY,
        height: trainCount * OPERATIONAL_PX_PER_TRAIN,
      },
    };
  }, [mockData.trains.length]);

  // Strategic layer
  const strategicLayers = useMemo(() => {
    if (opacities.strategic <= 0) return [];

    return [
      new SolidPolygonLayer<AggregatedCell>({
        id: 'strategic-heatmap',
        data: mockData.aggregatedByQuarter,
        getPolygon: (d) => {
          const x = d.periodIndex * STRATEGIC_CELL_WIDTH;
          const y = d.trainIndex * STRATEGIC_CELL_HEIGHT;
          return [
            [x, y],
            [x + STRATEGIC_CELL_WIDTH - 1, y],
            [x + STRATEGIC_CELL_WIDTH - 1, y + STRATEGIC_CELL_HEIGHT - 1],
            [x, y + STRATEGIC_CELL_HEIGHT - 1],
          ];
        },
        getFillColor: (d) => {
          const intensity = Math.min(1, d.utilizationPercent / 100);
          if (intensity < 0.5) {
            const t = intensity * 2;
            return [255, Math.round(243 - t * 50), Math.round(196 - t * 100), 255 * opacities.strategic];
          } else {
            const t = (intensity - 0.5) * 2;
            return [255, Math.round(193 - t * 100), Math.round(96 - t * 96), 255 * opacities.strategic];
          }
        },
        pickable: true,
        opacity: opacities.strategic,
        updateTriggers: {
          getFillColor: [opacities.strategic],
        },
      }),
    ];
  }, [mockData.aggregatedByQuarter, opacities.strategic]);

  // Tactical layer
  const tacticalLayers = useMemo(() => {
    if (opacities.tactical <= 0) return [];

    return [
      new SolidPolygonLayer<AggregatedCell>({
        id: 'tactical-bars',
        data: mockData.aggregatedByMonth,
        getPolygon: (d) => {
          const x = d.periodIndex * TACTICAL_CELL_WIDTH;
          const y = d.trainIndex * TACTICAL_CELL_HEIGHT;
          const barHeight = (d.utilizationPercent / 100) * (TACTICAL_CELL_HEIGHT - 2);
          return [
            [x + 1, y + TACTICAL_CELL_HEIGHT - 1 - barHeight],
            [x + TACTICAL_CELL_WIDTH - 2, y + TACTICAL_CELL_HEIGHT - 1 - barHeight],
            [x + TACTICAL_CELL_WIDTH - 2, y + TACTICAL_CELL_HEIGHT - 1],
            [x + 1, y + TACTICAL_CELL_HEIGHT - 1],
          ];
        },
        getFillColor: (d) => {
          if (d.hasConflict) return [239, 68, 68, 255 * opacities.tactical];
          const intensity = Math.min(1, d.utilizationPercent / 100);
          if (intensity > 0.8) return [239, 68, 68, 255 * opacities.tactical];
          if (intensity > 0.6) return [251, 191, 36, 255 * opacities.tactical];
          return [34, 197, 94, 255 * opacities.tactical];
        },
        pickable: true,
        opacity: opacities.tactical,
        updateTriggers: {
          getFillColor: [opacities.tactical],
        },
      }),
    ];
  }, [mockData.aggregatedByMonth, opacities.tactical]);

  // Operational layer
  const operationalLayers = useMemo(() => {
    if (opacities.operational <= 0) return [];

    interface TaskPolygon {
      polygon: [number, number][];
      task: Task;
      color: [number, number, number, number];
    }

    const taskPolygons: TaskPolygon[] = mockData.tasks.map((task) => {
      const startDay = daysBetween(TIME_RANGE.start, task.startDate);
      const duration = Math.max(1, daysBetween(task.startDate, task.endDate));

      const x = startDay * OPERATIONAL_PX_PER_DAY;
      const y = task.trainIndex * OPERATIONAL_PX_PER_TRAIN + 4;
      const w = duration * OPERATIONAL_PX_PER_DAY - 1;
      const h = 20;

      const mt = MAINTENANCE_TYPE_MAP.get(task.type);
      const baseColor = mt?.color ?? COLORS.task.default;

      return {
        polygon: [
          [x, y],
          [x + w, y],
          [x + w, y + h],
          [x, y + h],
        ],
        task,
        color: hexToRgba(baseColor, 255 * opacities.operational),
      };
    });

    return [
      // Background rows
      new SolidPolygonLayer<{ polygon: [number, number][]; index: number }>({
        id: 'operational-grid',
        data: mockData.trains.map((_, i) => ({
          polygon: [
            [0, i * OPERATIONAL_PX_PER_TRAIN],
            [worldDimensions.operational.width, i * OPERATIONAL_PX_PER_TRAIN],
            [worldDimensions.operational.width, (i + 1) * OPERATIONAL_PX_PER_TRAIN - 1],
            [0, (i + 1) * OPERATIONAL_PX_PER_TRAIN - 1],
          ],
          index: i,
        })),
        getPolygon: (d) => d.polygon,
        getFillColor: (d) => d.index % 2 === 0
          ? [250, 250, 250, 255 * opacities.operational]
          : [245, 245, 245, 255 * opacities.operational],
        pickable: false,
        opacity: opacities.operational * 0.8,
      }),
      // Task bars
      new SolidPolygonLayer<TaskPolygon>({
        id: 'operational-tasks',
        data: taskPolygons,
        getPolygon: (d) => d.polygon,
        getFillColor: (d) => {
          if (d.task.hasConflict) return [239, 68, 68, 255 * opacities.operational];
          return d.color;
        },
        pickable: true,
        opacity: opacities.operational,
        updateTriggers: {
          getFillColor: [opacities.operational],
        },
      }),
    ];
  }, [mockData.tasks, mockData.trains.length, worldDimensions.operational.width, opacities.operational]);

  // All layers
  const layers = useMemo(() => [
    ...strategicLayers,
    ...tacticalLayers,
    ...operationalLayers,
  ], [strategicLayers, tacticalLayers, operationalLayers]);

  // View state
  const viewState: ViewState = useMemo(() => {
    let targetX = cameraX;
    let targetY = cameraY;

    if (currentLOD === 'strategic') {
      targetX = cameraX * STRATEGIC_CELL_WIDTH / OPERATIONAL_PX_PER_DAY * 90;
      targetY = cameraY * STRATEGIC_CELL_HEIGHT;
    } else if (currentLOD === 'tactical') {
      targetX = cameraX * TACTICAL_CELL_WIDTH / OPERATIONAL_PX_PER_DAY * 30;
      targetY = cameraY * TACTICAL_CELL_HEIGHT;
    } else {
      targetX = cameraX * OPERATIONAL_PX_PER_DAY;
      targetY = cameraY * OPERATIONAL_PX_PER_TRAIN;
    }

    return {
      target: [targetX + canvasWidth / 2, targetY + canvasHeight / 2, 0],
      zoom: Math.log2(zoom),
    };
  }, [cameraX, cameraY, zoom, canvasWidth, canvasHeight, currentLOD]);

  // Handlers
  const handleZoomChange = useCallback((delta: number) => {
    setZoom((z) => Math.max(0.1, Math.min(5, z + delta)));
  }, []);

  const handleTimeRangeChange = useCallback((start: number, end: number) => {
    setTimeRangeStart(start);
    setTimeRangeEnd(end);
    // Sync camera X to start of selected range
    const dayOffset = daysBetween(TIME_RANGE.start, new Date(start));
    setCameraX(dayOffset);
  }, []);

  // Keyboard shortcuts
  useEffect(() => {
    if (!enableKeyboard) return;

    const handleKeyDown = (e: KeyboardEvent) => {
      switch (e.key) {
        case '+':
        case '=':
          handleZoomChange(0.1);
          break;
        case '-':
          handleZoomChange(-0.1);
          break;
        case '1':
          setZoom(0.2);
          break;
        case '2':
          setZoom(0.6);
          break;
        case '3':
          setZoom(1.8);
          break;
        case '4':
          setZoom(4.0);
          break;
        case 'Home':
          setZoom(initialZoom);
          setCameraX(0);
          setCameraY(0);
          break;
      }
    };

    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [enableKeyboard, handleZoomChange, initialZoom]);

  // Visible trains for sidebar
  const visibleTrains = useMemo(() => {
    const rowHeight = currentLOD === 'strategic' ? STRATEGIC_CELL_HEIGHT * zoom
      : currentLOD === 'tactical' ? TACTICAL_CELL_HEIGHT * zoom
      : OPERATIONAL_PX_PER_TRAIN * zoom;
    const startIndex = Math.max(0, Math.floor(cameraY));
    const visibleCount = Math.ceil(canvasHeight / Math.max(rowHeight, 20)) + 2;
    return mockData.trains.slice(startIndex, startIndex + visibleCount);
  }, [cameraY, canvasHeight, zoom, currentLOD, mockData.trains]);

  // View
  const views = new OrthographicView({
    id: 'fractal-view',
    flipY: false,
    controller: true,
  });

  // Timeline granularity
  const timelineGranularity = getGranularityForZoom(zoom);

  return (
    <div
      ref={containerRef}
      style={{ width, height, position: 'relative', background: '#f4f4f5', overflow: 'hidden' }}
    >
      {/* Navbar */}
      <Navbar style={{ height: NAVBAR_HEIGHT }}>
        <NavbarGroup align={Alignment.LEFT}>
          <Icon icon="train" size={18} style={{ marginRight: 8 }} />
          <NavbarHeading style={{ fontSize: 15, fontWeight: 600 }}>
            MMS Fractal Canvas
          </NavbarHeading>
          <NavbarDivider />
          <Tag
            intent={getLODIntent(currentLOD)}
            large
            style={{ minWidth: 100, textAlign: 'center' }}
          >
            {currentLOD.toUpperCase()}
          </Tag>
          <span style={{ marginLeft: 16, fontSize: 12, color: '#64748b' }}>
            {mockData.stats.totalTasks.toLocaleString()} tasks | {mockData.stats.totalTrains} trains
          </span>
        </NavbarGroup>
        <NavbarGroup align={Alignment.RIGHT}>
          <div style={{ display: 'flex', alignItems: 'center', gap: 16 }}>
            <div style={{ fontSize: 12 }}>
              <span style={{ color: '#64748b' }}>Zoom: </span>
              <span style={{ fontWeight: 600 }}>{zoom.toFixed(2)}x</span>
            </div>
            <ButtonGroup>
              <Tooltip content="Strategic (1)">
                <Button
                  small
                  intent={currentLOD === 'strategic' ? Intent.PRIMARY : Intent.NONE}
                  onClick={() => setZoom(0.2)}
                >
                  S
                </Button>
              </Tooltip>
              <Tooltip content="Tactical (2)">
                <Button
                  small
                  intent={currentLOD === 'tactical' ? Intent.WARNING : Intent.NONE}
                  onClick={() => setZoom(0.6)}
                >
                  T
                </Button>
              </Tooltip>
              <Tooltip content="Operational (3)">
                <Button
                  small
                  intent={currentLOD === 'operational' ? Intent.SUCCESS : Intent.NONE}
                  onClick={() => setZoom(1.8)}
                >
                  O
                </Button>
              </Tooltip>
              <Tooltip content="Execution (4)">
                <Button
                  small
                  intent={currentLOD === 'execution' ? Intent.DANGER : Intent.NONE}
                  onClick={() => setZoom(4.0)}
                >
                  E
                </Button>
              </Tooltip>
            </ButtonGroup>
            <ButtonGroup>
              <Button icon="minus" small onClick={() => handleZoomChange(-0.1)} />
              <Button icon="plus" small onClick={() => handleZoomChange(0.1)} />
              <Button icon="home" small onClick={() => {
                setZoom(initialZoom);
                setCameraX(0);
                setCameraY(0);
              }} />
            </ButtonGroup>
          </div>
        </NavbarGroup>
      </Navbar>

      {/* Main content */}
      <div style={{ display: 'flex', height: height - NAVBAR_HEIGHT }}>
        {/* Sidebar */}
        <Card
          style={{
            width: SIDEBAR_WIDTH,
            height: '100%',
            borderRadius: 0,
            padding: 0,
            overflow: 'hidden',
            borderRight: '1px solid #e2e8f0',
          }}
        >
          <div
            style={{
              padding: '8px 12px',
              borderBottom: '1px solid #e2e8f0',
              fontWeight: 600,
              fontSize: 12,
              background: '#f8fafc',
              height: TIMELINE_HEIGHT,
              display: 'flex',
              alignItems: 'center',
            }}
          >
            <Icon icon="train" size={12} style={{ marginRight: 6 }} />
            Trains ({mockData.trains.length})
          </div>
          <div style={{ overflowY: 'auto', height: canvasHeight }}>
            {visibleTrains.map((train) => (
              <div
                key={train.id}
                style={{
                  padding: '6px 12px',
                  borderBottom: '1px solid #f1f5f9',
                  fontSize: 10,
                  background: train.index % 2 === 0 ? '#fff' : '#fafafa',
                }}
              >
                <div style={{ fontWeight: 600, marginBottom: 2 }}>{train.name}</div>
                <Tag
                  minimal
                  intent={train.fleetId === 'kinki' ? Intent.SUCCESS : Intent.PRIMARY}
                  style={{ fontSize: 9 }}
                >
                  {train.fleetId === 'kinki' ? 'KNK' : 'ALT'}
                </Tag>
              </div>
            ))}
          </div>
        </Card>

        {/* Canvas area */}
        <div style={{ flex: 1, display: 'flex', flexDirection: 'column' }}>
          {/* Timeline Header */}
          <TimelineHeader
            startDate={TIME_RANGE.start}
            endDate={TIME_RANGE.end}
            width={canvasWidth}
            height={TIMELINE_HEIGHT}
            granularity={timelineGranularity}
            pxPerDay={OPERATIONAL_PX_PER_DAY * zoom}
            offsetX={cameraX * OPERATIONAL_PX_PER_DAY * zoom}
          />

          {/* deck.gl Canvas */}
          <div style={{ flex: 1, position: 'relative' }}>
            {/* Execution overlay (HTML) */}
            {opacities.execution > 0 && (
              <ExecutionOverlay
                tasks={mockData.tasks}
                trains={mockData.trains}
                cameraX={cameraX}
                cameraY={cameraY}
                zoom={zoom}
                width={canvasWidth}
                height={canvasHeight}
                opacity={opacities.execution}
              />
            )}

            {/* deck.gl layers */}
            {(opacities.strategic > 0 || opacities.tactical > 0 || opacities.operational > 0) && (
              <DeckGL
                width={canvasWidth}
                height={canvasHeight}
                views={views}
                viewState={viewState}
                layers={layers}
                getCursor={() => 'grab'}
                style={{ opacity: Math.max(opacities.strategic, opacities.tactical, opacities.operational) }}
              />
            )}

            {/* LOD indicator */}
            <div
              style={{
                position: 'absolute',
                bottom: 16,
                right: 16,
                background: 'white',
                padding: 12,
                borderRadius: 8,
                boxShadow: '0 2px 8px rgba(0,0,0,0.15)',
                fontSize: 11,
              }}
            >
              <div style={{ fontWeight: 600, marginBottom: 8 }}>Layer Visibility</div>
              {(['strategic', 'tactical', 'operational', 'execution'] as LODLevel[]).map((level) => (
                <div key={level} style={{ display: 'flex', alignItems: 'center', gap: 8, marginBottom: 4 }}>
                  <div
                    style={{
                      width: 40,
                      height: 6,
                      background: `linear-gradient(to right, ${getLODColor(level)} ${opacities[level] * 100}%, #e5e7eb ${opacities[level] * 100}%)`,
                      borderRadius: 3,
                    }}
                  />
                  <span>{level} ({Math.round(opacities[level] * 100)}%)</span>
                </div>
              ))}
            </div>

            {/* Zoom slider */}
            <Card
              style={{
                position: 'absolute',
                bottom: 16,
                left: 16,
                padding: 12,
                width: 200,
              }}
            >
              <div style={{ fontSize: 11, fontWeight: 600, marginBottom: 8 }}>
                Zoom Level
              </div>
              <Slider
                min={0.1}
                max={5}
                stepSize={0.05}
                value={zoom}
                onChange={setZoom}
                labelRenderer={(val) => `${val.toFixed(1)}x`}
                labelStepSize={1}
              />
              <div style={{ fontSize: 9, color: '#666', marginTop: 8 }}>
                <div>S: &lt;0.3x | T: 0.3-1.0x</div>
                <div>O: 1.0-3.0x | E: &gt;3.0x</div>
              </div>
            </Card>
          </div>

          {/* Time Scrubber */}
          {showTimeScrubber && (
            <TimeScrubber
              data={densityData}
              rangeStart={TIME_RANGE.start.getTime()}
              rangeEnd={TIME_RANGE.end.getTime()}
              selectionStart={timeRangeStart}
              selectionEnd={timeRangeEnd}
              onSelectionChange={handleTimeRangeChange}
              width={canvasWidth}
              height={SCRUBBER_HEIGHT}
              valueLabel="Tasks"
            />
          )}

          {/* Constraint Deck */}
          {showConstraintDeck && (
            <ConstraintDeck
              {...DEFAULT_CONSTRAINT_DECK_PROPS}
              width={canvasWidth}
              collapsed={constraintDeckCollapsed}
              onToggleCollapse={() => setConstraintDeckCollapsed(!constraintDeckCollapsed)}
            />
          )}
        </div>
      </div>
    </div>
  );
};

// =============================================================================
// EXECUTION OVERLAY
// =============================================================================

interface ExecutionOverlayProps {
  tasks: Task[];
  trains: Train[];
  cameraX: number;
  cameraY: number;
  zoom: number;
  width: number;
  height: number;
  opacity: number;
}

const ExecutionOverlay: React.FC<ExecutionOverlayProps> = ({
  tasks,
  trains,
  cameraX,
  cameraY,
  zoom,
  width,
  height,
  opacity,
}) => {
  const ROW_HEIGHT = 80;
  const EXEC_PX_PER_DAY = 80;

  const visibleTasks = useMemo(() => {
    const startTrain = Math.max(0, Math.floor(cameraY));
    const endTrain = Math.min(trains.length - 1, Math.ceil(cameraY + height / ROW_HEIGHT));
    return tasks
      .filter((task) => task.trainIndex >= startTrain && task.trainIndex <= endTrain)
      .slice(0, 50);
  }, [tasks, trains.length, cameraY, height]);

  const earliestTaskDay = useMemo(() => {
    if (visibleTasks.length === 0) return 0;
    return Math.min(...visibleTasks.map(t => daysBetween(TIME_RANGE.start, t.startDate)));
  }, [visibleTasks]);

  return (
    <div
      style={{
        position: 'absolute',
        top: 0,
        left: 0,
        width,
        height,
        overflow: 'hidden',
        background: '#f8fafc',
        opacity,
        pointerEvents: opacity > 0.5 ? 'auto' : 'none',
      }}
    >
      <div
        style={{
          position: 'absolute',
          top: 0,
          left: 0,
          right: 0,
          height: 40,
          background: 'white',
          borderBottom: '1px solid #e2e8f0',
          display: 'flex',
          alignItems: 'center',
          paddingLeft: 16,
          fontWeight: 600,
          fontSize: 12,
        }}
      >
        <Icon icon="calendar" size={14} style={{ marginRight: 8 }} />
        Execution View - {visibleTasks.length} tasks visible
      </div>

      <div
        style={{
          position: 'absolute',
          top: 40,
          left: 0,
          right: 0,
          bottom: 0,
          overflow: 'auto',
        }}
      >
        {visibleTasks.map((task) => {
          const startDay = daysBetween(TIME_RANGE.start, task.startDate);
          const duration = Math.max(1, daysBetween(task.startDate, task.endDate));
          const dayOffset = startDay - earliestTaskDay;

          const x = 16 + dayOffset * EXEC_PX_PER_DAY;
          const y = (task.trainIndex - Math.floor(cameraY)) * ROW_HEIGHT + 10;
          const w = Math.max(duration * EXEC_PX_PER_DAY - 10, 150);

          const mt = MAINTENANCE_TYPE_MAP.get(task.type);

          return (
            <Card
              key={task.id}
              interactive
              elevation={1}
              style={{
                position: 'absolute',
                left: x,
                top: y,
                width: w,
                height: 60,
                padding: 8,
                borderLeft: `4px solid ${mt?.color ?? '#94a3b8'}`,
              }}
            >
              <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start', marginBottom: 4 }}>
                <div style={{ fontSize: 10, fontWeight: 600 }}>{task.name}</div>
                <Tag
                  minimal
                  intent={
                    task.status === 'completed' ? Intent.SUCCESS :
                    task.status === 'in-progress' ? Intent.PRIMARY :
                    task.status === 'overdue' ? Intent.DANGER :
                    Intent.NONE
                  }
                  style={{ fontSize: 8 }}
                >
                  {task.status}
                </Tag>
              </div>
              <div style={{ fontSize: 9, color: '#64748b' }}>
                {task.durationHours}h | {task.manHours}mh | Pit {task.pitId}
              </div>
              {task.hasConflict && (
                <Tag intent={Intent.DANGER} style={{ position: 'absolute', top: 4, right: 4, fontSize: 8 }}>!</Tag>
              )}
            </Card>
          );
        })}
      </div>
    </div>
  );
};

export default FractalCanvasComplete;

/**
