    54→const LOD_DESCRIPTIONS: Record<LODLevel, string> = {
    55→  strategic: '12-Year Heatmap Overview',
    56→  tactical: 'Quarterly Stacked Bars',
    57→  operational: 'Monthly DNA Gantt',
    58→  execution: 'Weekly Task Details',
