    61→// =============================================================================
    62→// OPACITY CALCULATION
    63→// =============================================================================
    64→
    65→/**
    66→ * Calculate layer opacities based on current zoom level.
    67→ * Uses smooth crossfade transitions near thresholds.
    68→ */
    69→function calculateLayerOpacities(zoom: number): LayerOpacities {
    70→  const { strategic, tactical, operational } = LOD_THRESHOLDS;
    71→
    72→  // Helper: smooth step function for crossfade
    73→  const smoothStep = (value: number, edge0: number, edge1: number): number => {
    74→    const t = Math.max(0, Math.min(1, (value - edge0) / (edge1 - edge0)));
    75→    return t * t * (3 - 2 * t); // Smooth Hermite interpolation
    76→  };
    77→
    78→  // Calculate fade factors for each threshold
    79→  const fadeStrategicToTactical = smoothStep(
    80→    zoom,
    81→    strategic - CROSSFADE_RANGE,
    82→    strategic + CROSSFADE_RANGE
    83→  );
    84→
    85→  const fadeTacticalToOperational = smoothStep(
    86→    zoom,
    87→    tactical - CROSSFADE_RANGE,
    88→    tactical + CROSSFADE_RANGE
    89→  );
    90→
    91→  const fadeOperationalToExecution = smoothStep(
    92→    zoom,
    93→    operational - CROSSFADE_RANGE,
    94→    operational + CROSSFADE_RANGE
    95→  );
    96→
    97→  // Calculate final opacities
    98→  return {
    99→    strategic: 1 - fadeStrategicToTactical,
   100→    tactical: fadeStrategicToTactical * (1 - fadeTacticalToOperational),
   101→    operational: fadeTacticalToOperational * (1 - fadeOperationalToExecution),
   102→    execution: fadeOperationalToExecution,
   103→  };
   104→}
