   124→        items.push({ row, col, intensity });
   125→      }
   126→    }
   127→    return items;
   128→  }, []);
   129→
   130→  return (
   131→    <div
   132→      style={{
   133→        position: 'absolute',
   134→        inset: 0,
   135→        opacity,
   136→        transition: 'opacity 50ms ease-out',
   137→        display: 'grid',
   138→        gridTemplateColumns: 'repeat(12, 1fr)',
   139→        gridTemplateRows: 'repeat(8, 1fr)',
   140→        gap: 2,
   141→        padding: 40,
   142→      }}
