   154→            color: intensity > 0.5 ? 'white' : COLORS.text.secondary,
   155→            fontWeight: 500,
   156→          }}
   157→        >
   158→          {Math.round(intensity * 100)}%
   159→        </div>
   160→      ))}
   161→    </div>
   162→  );
   163→}
